const axios = require('axios');

async function calculateForUser(username) {
    const headers = {
        'Accept': 'application/vnd.github.v3+json',
        'User-Agent': 'node.js'
    };

    try {
        const userRes = await axios.get(`https://api.github.com/users/${username}`, { headers });
        const user = userRes.data;

        const reposRes = await axios.get(`https://api.github.com/users/${username}/repos?per_page=100`, { headers });
        const repos = reposRes.data;

        let totalStars = 0;
        let totalForks = 0;
        const languages = {};

        for (const repo of repos) {
            totalStars += repo.stargazers_count;
            totalForks += repo.forks_count;
            if (repo.language) {
                languages[repo.language] = (languages[repo.language] || 0) + 1;
            }
        }

        const primaryLanguage = Object.keys(languages).sort((a, b) => languages[b] - languages[a])[0] || 'Unknown';

        const createdAt = new Date(user.created_at);
        const now = new Date();
        const accountAgeMs = now.getTime() - createdAt.getTime();
        const accountAgeYears = accountAgeMs / (1000 * 60 * 60 * 24 * 365.25);

        const atk = Math.floor((Math.sqrt(totalStars) * 2 + Math.sqrt(totalForks)) * 10) + 10;
        const def = Math.floor(user.public_repos * 15 + (user.public_gists || 0) * 20) + Math.floor(user.followers * 0.5) + 50;
        const hp = Math.floor(accountAgeYears * 50) + Math.floor(user.public_repos * 5) + 200 + Math.floor(atk * 3);

        let rarity = 'Common';
        const score = user.followers * 2 + totalStars;
        if (score > 50000 || (user.company && ['google', 'microsoft', 'vercel', 'facebook', 'meta'].some(c => user.company.toLowerCase().includes(c)))) {
            rarity = 'Legendary';
        } else if (score > 10000) {
            rarity = 'Epic';
        } else if (score > 2500) {
            rarity = 'Rare';
        } else if (score > 500) {
            rarity = 'Uncommon';
        }

        return {
            username: user.login,
            name: user.name || user.login,
            atk,
            def,
            hp,
            rarity,
            primaryLanguage,
            totalStars,
            totalForks,
            followers: user.followers,
            repos: user.public_repos,
            accountAgeYears: accountAgeYears.toFixed(2)
        };

    } catch (err) {
        console.error(`Error for ${username}: ${err.message}`);
        return null;
    }
}

async function main() {
    const users = ['CaioMizerkowski', 'kalliub', 'PINTO0309', 'RainhaVisenya'];
    const allStats = [];
    for (const user of users) {
        const stats = await calculateForUser(user);
        if (stats) allStats.push(stats);
    }
    console.log(JSON.stringify(allStats, null, 2));
}

main();

/**
 * Migration Script: Recalculate ATK, DEF, HP for all cards.
 * 
 * For each card in the database:
 *   1. Fetch fresh data from GitHub API using githubUsername
 *   2. Compute new ATK, DEF, HP with rebalanced formulas
 *   3. Update the card (rarity and primaryLanguage are NOT changed)
 *   4. Log old vs new stats for review
 *
 * Usage: node migrate_stats.js
 */

const { PrismaClient } = require('@prisma/client');
const axios = require('axios');
const fs = require('fs');
const path = require('path');

// Load .env manually (dotenv not installed)
const envPath = path.join(__dirname, '.env');
if (fs.existsSync(envPath)) {
  const envContent = fs.readFileSync(envPath, 'utf-8');
  for (const line of envContent.split('\n')) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const eqIdx = trimmed.indexOf('=');
    if (eqIdx === -1) continue;
    const key = trimmed.slice(0, eqIdx).trim();
    let val = trimmed.slice(eqIdx + 1).trim();
    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
      val = val.slice(1, -1);
    }
    if (!process.env[key]) process.env[key] = val;
  }
}

const prisma = new PrismaClient();

const GITHUB_TOKEN = process.env.GITHUB_TOKEN;
const headers = {
  Authorization: GITHUB_TOKEN ? `token ${GITHUB_TOKEN}` : '',
  Accept: 'application/vnd.github.v3+json',
  'User-Agent': 'GitGatcha-Migration',
};

// Rate limit helper: wait between requests
const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

async function fetchGitHubData(username) {
  const userRes = await axios.get(`https://api.github.com/users/${username}`, { headers });
  const user = userRes.data;

  const reposRes = await axios.get(`https://api.github.com/users/${username}/repos?per_page=100`, { headers });
  const repos = reposRes.data;

  let totalStars = 0;
  let totalForks = 0;
  for (const repo of repos) {
    totalStars += repo.stargazers_count;
    totalForks += repo.forks_count;
  }

  const accountAgeMs = new Date().getTime() - new Date(user.created_at).getTime();
  const accountAgeYears = accountAgeMs / (1000 * 60 * 60 * 24 * 365.25);

  return {
    totalStars,
    totalForks,
    publicRepos: user.public_repos,
    publicGists: user.public_gists || 0,
    followers: user.followers,
    accountAgeYears,
  };
}

function calculateNewStats(data) {
  const atk = Math.floor((Math.sqrt(data.totalStars) * 2 + Math.sqrt(data.totalForks)) * 10) + 10;
  const def = Math.floor(data.publicRepos * 15 + data.publicGists * 20) + Math.floor(data.followers * 0.5) + 50;
  const hp  = Math.floor(data.accountAgeYears * 50) + Math.floor(data.publicRepos * 5) + 200 + Math.floor(atk * 3);
  return { atk, def, hp };
}

async function main() {
  console.log('=== GitGatcha Stat Rebalance Migration ===\n');

  const cards = await prisma.card.findMany({
    select: { id: true, githubUsername: true, name: true, atk: true, def: true, hp: true },
  });

  console.log(`Found ${cards.length} cards to migrate.\n`);

  let updated = 0;
  let failed = 0;

  for (const card of cards) {
    try {
      const ghData = await fetchGitHubData(card.githubUsername);
      const newStats = calculateNewStats(ghData);

      await prisma.card.update({
        where: { id: card.id },
        data: { atk: newStats.atk, def: newStats.def, hp: newStats.hp },
      });

      console.log(`✅ ${card.githubUsername} (${card.name})`);
      console.log(`   ATK: ${card.atk} → ${newStats.atk}`);
      console.log(`   DEF: ${card.def} → ${newStats.def}`);
      console.log(`   HP:  ${card.hp} → ${newStats.hp}`);
      console.log('');

      updated++;

      // Respect GitHub API rate limits (~5000/hr with token → ~1.4/sec)
      await sleep(800);
    } catch (err) {
      console.log(`❌ FAILED: ${card.githubUsername} — ${err.message}`);
      failed++;
      await sleep(800);
    }
  }

  console.log('=== Migration Complete ===');
  console.log(`Updated: ${updated} | Failed: ${failed} | Total: ${cards.length}`);

  await prisma.$disconnect();
}

main().catch(err => {
  console.error('Fatal error:', err);
  prisma.$disconnect();
  process.exit(1);
});

const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

async function main() {
  // Delete existing entries to avoid duplicates and ensure clean test
  await prisma.changelogEntry.deleteMany({});
  console.log('Cleared existing changelog entries.');

  const changelog = await prisma.changelogEntry.create({
    data: {
      version: 'v1.1.0 — March 14, 2026',
      title: 'Forge, Stamina & Battle Systems Mega Update',
      body: `### 🛠️ Forge System
Added the **Forge panel**, where you can search any developer by GitHub username or profile link and invoke their card using language fragments and BITS. 

- Accumulate fragments by opening packs or receiving duplicate cards.
- Spend fragments to **guarantee** a specific card you want. 
- Add developers to your **Wishlist** to track fragment progress for each one.

***

