main().catch(console.error).finally(() => prisma.$disconnect());

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { getCardType } from '@/lib/battleResolver';
import { getCardStamina } from '@/lib/staminaService';

// POST: Create a friend challenge (challenger picks their 3-card team)
export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const { defenderUsername, cardIds } = await req.json();

    if (!Array.isArray(cardIds) || cardIds.length !== 3) {
      return NextResponse.json({ error: 'You must select exactly 3 cards for your team' }, { status: 400 });
    }

    // Look up defender by username
    const defender = await prisma.user.findUnique({ where: { username: defenderUsername } });
    if (!defender) return NextResponse.json({ error: 'Player not found' }, { status: 404 });
    if (defender.id === userId) return NextResponse.json({ error: 'You cannot challenge yourself' }, { status: 400 });

    // Verify card ownership and build team payload
    const uniqueCardIds = Array.from(new Set(cardIds));
    const userCards = await prisma.userCard.findMany({
      where: { userId, cardId: { in: uniqueCardIds } },
      include: { card: true },
    });

    const requiredCounts: Record<string, number> = {};
    for (const id of cardIds as string[]) {
      requiredCounts[id] = (requiredCounts[id] || 0) + 1;
    }

    const ownedCounts: Record<string, number> = {};
    for (const uc of userCards) {
      ownedCounts[uc.cardId] = (ownedCounts[uc.cardId] || 0) + 1;
    }

    for (const [id, count] of Object.entries(requiredCounts)) {
      if (!ownedCounts[id] || ownedCounts[id] < count) {
        return NextResponse.json({ error: 'One or more cards not found in your collection' }, { status: 404 });
      }
    }

    // Preserve chosen card order
    // Validate stamina
    for (const id of cardIds as string[]) {
      const uc = userCards.find(u => u.cardId === id);
      if (uc) {
        const currentStamina = getCardStamina(uc);
        if (currentStamina === 0) {
          return NextResponse.json({ error: `Card ${uc.card.name} is exhausted and cannot battle` }, { status: 400 });
        }
      }
    }

    const challengerTeam = cardIds.map(id => {
      const uc = userCards.find(u => u.cardId === id)!;
      const c = uc.card;
      return {
        id: uc.id, // Store userCardId as id so we can deduct stamina later
        cardId: c.id,
        name: c.name,
        avatarUrl: c.avatarUrl,
        atk: c.atk,
        def: c.def,
        hp: c.hp,
        maxHp: c.hp,
        stamina: getCardStamina(uc),
        rarity: c.rarity,
        primaryLanguage: c.primaryLanguage,
        type: getCardType(c),
      };
    });

    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours

    const battle = await prisma.battle.create({
      data: {
        challengerId: userId,
        defenderId: defender.id,
        challengerTeam: challengerTeam as any,
        status: 'PENDING',
        isRandom: false,
        expiresAt,
      },
      include: {
        challenger: { select: { id: true, username: true, image: true } },
      },
    });

    return NextResponse.json({ success: true, battle });

  } catch (error) {
    console.error('Challenge creation error:', error);
    return NextResponse.json({ error: 'Failed to create challenge' }, { status: 500 });
  }
}

// GET: Get pending challenges for current user
export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    // Expire old challenges
    await prisma.battle.updateMany({
      where: { status: 'PENDING', expiresAt: { lt: new Date() } },
      data: { status: 'EXPIRED' },
    });

    // Fetch incoming challenges
    const incoming = await prisma.battle.findMany({
      where: { defenderId: userId, status: 'PENDING' },
      include: { challenger: { select: { id: true, username: true, image: true } } },
      orderBy: { createdAt: 'desc' },
    });

    // Fetch outgoing challenges
    const outgoing = await prisma.battle.findMany({
      where: { challengerId: userId, status: 'PENDING' },
      include: { defender: { select: { id: true, username: true, image: true } } },
      orderBy: { createdAt: 'desc' },
    });

    return NextResponse.json({ incoming, outgoing });

  } catch (error) {
    console.error('Challenge fetch error:', error);
    return NextResponse.json({ error: 'Failed to fetch challenges' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { getCardStamina, STAMINA_RECOVERY_RATE_PER_HOUR, MAX_STAMINA } from '@/lib/staminaService';

export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { userCardId } = await req.json();

    if (!userCardId) {
      return NextResponse.json({ error: 'Missing userCardId' }, { status: 400 });
    }

    const userCard = await prisma.userCard.findUnique({
      where: { id: userCardId }
    });

    if (!userCard || userCard.userId !== userId) {
      return NextResponse.json({ error: 'Card not found or unowned' }, { status: 403 });
    }

    // Check if player has enough BITS (100)
    const user = await prisma.user.findUnique({ where: { id: userId } });
    if (!user || user.currency < 100) {
      return NextResponse.json({ error: 'Insufficient BITS' }, { status: 400 });
    }

    // Deduct exact amount
    await prisma.user.update({
      where: { id: userId },
      data: {
        currency: { decrement: 100 }
      }
    });

    // Update stamina and reset lastUsedAt
    const updatedUserCard = await prisma.userCard.update({
      where: { id: userCardId },
      data: {
        stamina: 100,
        lastUsedAt: new Date()
      }
    });

    return NextResponse.json({ success: true, updatedUserCard });
  } catch (error) {
    console.error('Instant recover error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { fetchGitHubUserStats } from '@/lib/githubService';
import { getInvocationCost } from '@/lib/forgeService';

export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const { username } = await req.json();
    if (!username) return NextResponse.json({ error: 'Username required' }, { status: 400 });

    const user = await prisma.user.findUnique({ where: { id: session.user.id } });
    if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 });

    const wishlist: any[] = Array.isArray(user.wishlist) ? [...user.wishlist] : [];

    if (wishlist.length >= 5) {
      return NextResponse.json({ error: 'Wishlist is full (max 5)' }, { status: 400 });
    }

    // Check if already in wishlist
    if (wishlist.some(w => w && w.username && w.username.toLowerCase() === username.toLowerCase())) {
      return NextResponse.json({ error: 'Already in wishlist' }, { status: 400 });
    }

    const stats = await fetchGitHubUserStats(username);
    if (!stats) return NextResponse.json({ error: 'Developer not found' }, { status: 404 });
    if (!stats.primaryLanguage || stats.primaryLanguage === 'Unknown') {
      return NextResponse.json({ error: 'Developer lacks a primary language' }, { status: 400 });
    }

    const { fragments } = getInvocationCost(stats.rarity);

    const wishlistItem = {
      username: stats.githubUsername,
      name: stats.name || stats.githubUsername,
      avatarUrl: stats.avatarUrl,
      primaryLanguage: stats.primaryLanguage,
      rarity: stats.rarity,
      fragmentsRequired: fragments
    };

    wishlist.push(wishlistItem);

    await prisma.user.update({
      where: { id: user.id },
      data: { wishlist }
    });

    return NextResponse.json({ success: true, wishlist });
  } catch (error) {
    console.error('Wishlist POST error:', error);
    return NextResponse.json({ error: 'Failed to add to wishlist' }, { status: 500 });
  }
}

export async function DELETE(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const { searchParams } = new URL(req.url);
    const username = searchParams.get('username');

    if (!username) return NextResponse.json({ error: 'Username required' }, { status: 400 });

    const user = await prisma.user.findUnique({ where: { id: session.user.id } });
    if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 });

    let wishlist: any[] = Array.isArray(user.wishlist) ? [...user.wishlist] : [];
    wishlist = wishlist.filter(w => w && w.username && w.username.toLowerCase() !== username.toLowerCase());

    await prisma.user.update({
      where: { id: user.id },
      data: { wishlist }
    });

    return NextResponse.json({ success: true, wishlist });
  } catch (error) {
    console.error('Wishlist DELETE error:', error);
    return NextResponse.json({ error: 'Failed to remove from wishlist' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { prisma } from '@/lib/prisma';

export async function GET(req: Request) {
  try {
    const session = await getServerSession();
    if (!session || !session.user?.email) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const currentUser = await prisma.user.findUnique({
      where: { email: session.user.email },
    });

    if (!currentUser) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    // Get where user sent request and it was accepted, or where user received request and accepted it
    const friendships = await prisma.friendship.findMany({
      where: {
        OR: [
          { userId: currentUser.id, status: 'ACCEPTED' },
          { friendId: currentUser.id, status: 'ACCEPTED' },
        ],
      },
      include: {
        user: { select: { id: true, username: true, level: true } },
        friend: { select: { id: true, username: true, level: true } },
      },
    });

    // Format friends list to normalize who is the friend
    const friends = friendships.map(f => {
      const isCurrentUserSender = f.userId === currentUser.id;
      const friendData = isCurrentUserSender ? f.friend : f.user;

      return {
        friendshipId: f.id,
        user: friendData,
        createdAt: f.createdAt,
      };
    });

    // Pending incoming requests
    const pendingRequests = await prisma.friendship.findMany({
      where: {
        friendId: currentUser.id,
        status: 'PENDING',
      },
      include: {
        user: { select: { id: true, username: true, level: true } },
      },
    });

    // Pending outgoing requests
    const outgoingRequests = await prisma.friendship.findMany({
      where: {
        userId: currentUser.id,
        status: 'PENDING',
      },
      include: {
        friend: { select: { id: true, username: true, level: true } },
      },
    });

    return NextResponse.json({ 
      friends, 
      pendingRequests: pendingRequests.map(r => ({ id: r.id, user: r.user, createdAt: r.createdAt })),
      outgoingRequests: outgoingRequests.map(r => ({ id: r.id, user: r.friend, createdAt: r.createdAt })) 
    });
  } catch (error) {
    console.error('Error fetching friends:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { openBoosterPack } from '@/lib/boosterService';
import { advanceMissionProgress } from '@/lib/economyService';
import { grantXP, InventoryItem, XP_AMOUNTS } from '@/lib/xpService';

export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const { packId } = await req.json();
    if (!packId) return NextResponse.json({ error: 'Pack ID required' }, { status: 400 });

    const user = await prisma.user.findUnique({ where: { id: userId } });
    if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 });

    const inventory: InventoryItem[] = Array.isArray(user.inventory)
      ? (user.inventory as unknown as InventoryItem[])
      : [];

    // Find the first instance of this pack in inventory
    const packIndex = inventory.findIndex(item => item.packId === packId);
    if (packIndex === -1) {
      return NextResponse.json({ error: 'Pack not found in inventory' }, { status: 404 });
    }

    // Remove the pack from inventory
    const updatedInventory = [...inventory];
    updatedInventory.splice(packIndex, 1);

    await prisma.user.update({
      where: { id: userId },
      data: { inventory: updatedInventory as any },
    });

    // Open the booster pack
    const { newCards, packDropFragments } = await openBoosterPack(userId, packId);

    // Grant XP for opening a booster
    const xpResult = await grantXP(userId, XP_AMOUNTS.OPEN_BOOSTER);

    // Process missions async
    Promise.all([
      advanceMissionProgress(userId, 'OPEN_BOOSTER'),
      ...newCards.map(c => advanceMissionProgress(userId, 'COLLECT_RARITY', c.rarity)),
      ...newCards.map(c => advanceMissionProgress(userId, 'COLLECT_LANGUAGE', c.primaryLanguage || 'Unknown')),
    ]).catch(console.error);

    return NextResponse.json({
      success: true,
      cards: newCards,
      packDropFragments,
      xpGained: XP_AMOUNTS.OPEN_BOOSTER,
      xpResult,
    });
  } catch (error) {
    console.error('Open pack error:', error);
    return NextResponse.json({ error: 'Failed to open pack' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { getPackById, getSerializablePacks } from '@/lib/packDefinitions';
import { InventoryItem } from '@/lib/xpService';

export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { inventory: true },
    });

    if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 });

    const inventory: InventoryItem[] = Array.isArray(user.inventory)
      ? (user.inventory as unknown as InventoryItem[])
      : [];

    // Group packs by packId with count
    const packCounts: Record<string, { count: number; packId: string; packName: string; items: InventoryItem[] }> = {};
    for (const item of inventory) {
      if (!packCounts[item.packId]) {
        packCounts[item.packId] = { count: 0, packId: item.packId, packName: item.packName, items: [] };
      }
      packCounts[item.packId].count++;
      packCounts[item.packId].items.push(item);
    }

    // Enrich with pack visual data
    const allPacks = getSerializablePacks();
    const enrichedInventory = Object.values(packCounts).map(group => {
      const packDef = allPacks.find(p => p.id === group.packId);
      return {
        packId: group.packId,
        packName: group.packName,
        count: group.count,
        visualTheme: packDef?.visualTheme || null,
        cardCount: packDef?.cardCount || 5,
        guaranteedMinRarity: packDef?.guaranteedMinRarity || null,
        category: packDef?.category || 'unknown',
        description: packDef?.description || '',
      };
    });

    return NextResponse.json({ inventory: enrichedInventory });
  } catch (error) {
    console.error('Inventory error:', error);
    return NextResponse.json({ error: 'Failed to fetch inventory' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { prisma } from '@/lib/prisma';
import { authOptions } from '@/lib/auth';

export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const dbUser = await prisma.user.findUnique({
      where: { id: userId },
      select: { notifications: true, pendingRewards: true }
    });

    if (!dbUser) return NextResponse.json({ error: 'User not found' }, { status: 404 });

    // Pending incoming friend requests
    const friendRequests = await prisma.friendship.findMany({
      where: {
        friendId: userId,
        status: 'PENDING',
      },
      include: {
        user: { select: { id: true, username: true, level: true } },
      },
      orderBy: { createdAt: 'desc' },
    });

    // Pending incoming battle challenges
    const battleChallenges = await prisma.battle.findMany({
      where: {
        defenderId: userId,
        status: 'PENDING',
        expiresAt: { gt: new Date() },
      },
      include: {
        challenger: { select: { id: true, username: true } },
        challengerCard: true,
      },
      orderBy: { createdAt: 'desc' },
    });

    const standardNotifications = [
      ...friendRequests.map(fr => ({
        id: fr.id,
        type: 'friend_request' as const,
        from: fr.user.username || 'Unknown',
        message: `${fr.user.username} wants to be your friend`,
        actionUrl: '/friends',
        createdAt: fr.createdAt,
        read: false,
      })),
      ...battleChallenges.map(bc => ({
        id: bc.id,
        type: 'battle_challenge' as const,
        from: bc.challenger.username || 'Unknown',
        message: `${bc.challenger.username} challenged you to a 3v3 battle!`,
        actionUrl: '/battle',
        createdAt: bc.createdAt,
        read: false,
      })),
    ];

    const unreadDbNotifications = Array.isArray(dbUser.notifications) 
      ? (dbUser.notifications as any[]).filter(n => !n.read).map(n => ({
          ...n,
          createdAt: new Date(n.timestamp),
        }))
      : [];

    const allNotifications = [...standardNotifications, ...unreadDbNotifications].sort(
      (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );

    return NextResponse.json({ 
      notifications: allNotifications, 
      count: allNotifications.length,
      pendingRewards: dbUser.pendingRewards || [] 
    });
  } catch (error) {
    console.error('Error fetching notifications:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

export async function POST(request: Request) {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const body = await request.json();
    const { notificationId, markAll } = body;

    const dbUser = await prisma.user.findUnique({
      where: { id: userId },
      select: { notifications: true }
    });

    if (!dbUser) return NextResponse.json({ error: 'User not found' }, { status: 404 });

    let updatedNotifications = Array.isArray(dbUser.notifications) ? [...(dbUser.notifications as any[])] : [];

    if (markAll) {
      updatedNotifications = updatedNotifications.map(n => ({ ...n, read: true }));
    } else if (notificationId) {
      updatedNotifications = updatedNotifications.map(n => 
        n.id === notificationId ? { ...n, read: true } : n
      );
    }

    await prisma.user.update({
      where: { id: userId },
      data: { notifications: updatedNotifications as any }
    });

    return NextResponse.json({ success: true, count: updatedNotifications.filter(n => !n.read).length });

  } catch (error) {
    console.error('Error updating notifications:', error);
    return NextResponse.json({ error: 'Failed to update notifications' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(
  req: Request,
  { params }: { params: Promise<{ username: string }> }
) {
  try {
    const resolvedParams = await params;

    if (!resolvedParams.username) {
      return NextResponse.json({ error: 'Username is required' }, { status: 400 });
    }

    const username = decodeURIComponent(resolvedParams.username);

    const uncapitalizedUsername = username.toLowerCase(); // Handle case sensitivity depending on how we store it, assume DB might be case-insensitive for unique constraints, but we can do a precise check
    // Fetch user details
    const userProfile = await prisma.user.findFirst({
      where: { 
        OR: [
          { username: { equals: username, mode: 'insensitive' } },
          { name: { equals: username, mode: 'insensitive' } }
        ]
      },
      include: {
        cards: {
            include: {
                card: true,
            }
        },
        battlesAsChallenger: {
          select: {
            winnerId: true,
            status: true,
          }
        },
        battlesAsDefender: {
          select: {
            winnerId: true,
            status: true,
          }
        },
        friendships: {
            where: { status: 'ACCEPTED' },
            include: {
              friend: { select: { id: true, username: true, level: true } },
            }
        },
        friendRequests: {
            where: { status: 'ACCEPTED' },
            include: {
              user: { select: { id: true, username: true, level: true } },
            }
        }
      } as any,
    }) as any;

    if (!userProfile) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    // Calculate derived stats
    const totalCards = userProfile.cards.length;
    const completedBattles = [...userProfile.battlesAsChallenger, ...userProfile.battlesAsDefender].filter(
        b => b.status === 'COMPLETED'
    );
    const battlesWon = completedBattles.filter(b => b.winnerId === userProfile.id).length;
    const battlesLost = completedBattles.length - battlesWon;

    // Build normalized friends list from both directions
    const friendsList = [
      ...userProfile.friendships.map((f: any) => ({
        id: f.friend.id,
        username: f.friend.username,
        level: f.friend.level,
      })),
      ...userProfile.friendRequests.map((f: any) => ({
        id: f.user.id,
        username: f.user.username,
        level: f.user.level,
      })),
    ];
    const friendsCount = friendsList.length;

    // Get top cards (highest stats or rarity, we'll simplify and list some cards)
    const topCards = userProfile.cards
        .map((uc: any) => ({ ...uc.card, quantity: uc.quantity, isShiny: uc.isShiny }))
        .sort((a: any, b: any) => (b.atk + b.def + b.hp) - (a.atk + a.def + a.hp))
        .slice(0, 5); // top 5 strongest cards

    // Get showcase cards (loyalty system Hall of Fame)
    // Showcase cards must be Reliable tier or higher, and ordered by showcaseOrder
    const showcaseCards = userProfile.cards
        .filter((uc: any) => uc.loyaltyTier === 'reliable' || uc.loyaltyTier === 'legendary_bond' || uc.loyaltyTier === 'eternal')
        .sort((a: any, b: any) => {
            if (a.showcaseOrder !== null && b.showcaseOrder !== null) return a.showcaseOrder - b.showcaseOrder;
            if (a.showcaseOrder !== null) return -1;
            if (b.showcaseOrder !== null) return 1;
            return b.loyaltyCount - a.loyaltyCount; // fallback to highest loyalty
        })
        .slice(0, 6)
        .map((uc: any) => ({
            ...uc.card,
            quantity: uc.quantity,
            isShiny: uc.isShiny,
            loyaltyTier: uc.loyaltyTier,
            loyaltyCount: Math.max(0, uc.loyaltyCount),
        }));

    // Check for Prestige Badge: Legendary Bond (has any card with 100+ battles)
    const hasLegendaryBondPrestige = userProfile.cards.some((uc: any) => uc.loyaltyCount >= 100);

    // Check for level ups in the last 24 hours
    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
    const notifications = Array.isArray(userProfile.notifications) ? userProfile.notifications as any[] : [];
    const hasLeveledUpRecently = notifications.some((n: any) => {
        if (n.type === 'LEVEL_UP') {
            const notifDate = new Date(n.timestamp);
            return notifDate >= oneDayAgo;
        }
        return false;
    });

    return NextResponse.json({ 
        user: {
            id: userProfile.id,
            username: userProfile.username || userProfile.name || 'Unknown',
            level: userProfile.level,
            xp: userProfile.xp,
            rating: userProfile.rating,
            createdAt: userProfile.createdAt,
        },
        stats: {
            totalCards,
            battlesWon,
            battlesLost,
            totalBattles: completedBattles.length,
            friendsCount,
        },
        topCards,
        showcaseCards,
        friends: friendsList,
        hasLeveledUpRecently,
        hasLegendaryBondPrestige,
    });
  } catch (error) {
    console.error('Error fetching user profile:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { getPackById } from '@/lib/packDefinitions';
import { InventoryItem } from '@/lib/xpService';

export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    let packId: string | undefined;
    try {
      const body = await req.json();
      packId = body.packId;
    } catch {
      // No body or invalid JSON
    }

    if (!packId) {
      return NextResponse.json({ error: 'Pack ID required' }, { status: 400 });
    }

    const pack = getPackById(packId);
    if (!pack) {
      return NextResponse.json({ error: 'Pack not found' }, { status: 404 });
    }

    const user = await prisma.user.findUnique({ where: { id: userId } });
    if (!user || user.currency < pack.cost) {
      return NextResponse.json({ error: 'Not enough Bits' }, { status: 400 });
    }

    // Build new inventory item
    const newItem: InventoryItem = {
      packId: pack.id,
      packName: pack.name,
      acquiredAt: new Date().toISOString(),
      source: 'purchase',
    };

    const currentInventory: InventoryItem[] = Array.isArray(user.inventory)
      ? (user.inventory as unknown as InventoryItem[])
      : [];

    // Deduct cost and add pack to inventory
    await prisma.user.update({
      where: { id: userId },
      data: {
        currency: { decrement: pack.cost },
        inventory: [...currentInventory, newItem] as any,
      },
    });

    return NextResponse.json({
      success: true,
      newCurrency: user.currency - pack.cost,
      packName: pack.name,
      packId: pack.id,
    });
  } catch (error) {
    console.error('Purchase error:', error);
    return NextResponse.json({ error: 'Failed to purchase pack' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { getCardStamina } from '@/lib/staminaService';

/**
 * Handle GET to fetch which cards are currently marked as inActiveTeam.
 */
export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const activeCards = await prisma.userCard.findMany({
      where: {
        userId,
        inActiveTeam: true
      },
      select: {
        id: true,
        cardId: true
      }
    });

    return NextResponse.json({ activeCards });
  } catch (error) {
    console.error('Fetch active team error:', error);
    return NextResponse.json({ error: 'Failed to fetch active team' }, { status: 500 });
  }
}

/**
 * Handle POST to update which cards are in active team.
 * This triggers a stamina sync and marks the rest as not in active team.
 */
export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    const userId = session?.user?.id;
    if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const { cardIds } = await req.json(); // These are the global cardIds
    if (!Array.isArray(cardIds) || cardIds.length > 3) {
      return NextResponse.json({ error: 'Invalid payload' }, { status: 400 });
    }

    // First fetch ALL user cards to properly sync them before toggling state
    const userCards = await prisma.userCard.findMany({
      where: { userId }
    });

    const now = new Date();

    const updates: any[] = [];

    // Update the whole collection by toggling inActiveTeam
    for (const uc of userCards) {
      const isNowActive = cardIds.includes(uc.cardId);

      if (uc.inActiveTeam !== isNowActive) {
        // Changing state -> we MUST calculate their current stamina and save it!
        // So that from this moment onward, the passive recovery resumes (if going inactive)
        // or pauses (if going active) at the correct current stamina value.
        const actualStamina = getCardStamina(uc);

        updates.push(prisma.userCard.update({
          where: { id: uc.id },
          data: {
            stamina: actualStamina,
            lastUsedAt: now,
            inActiveTeam: isNowActive
          }
        }));
      }
    }

    if (updates.length > 0) {
      await prisma.$transaction(updates);
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Update active team error:', error);
    return NextResponse.json({ error: 'Failed to update active team' }, { status: 500 });
  }
}

