                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
          {paginatedData.length === 0 ? (
            <div className="col-span-full py-12 text-center text-slate-500 bg-black border border-slate-800 rounded-xl">
              No records found in the database.
            </div>
          ) : (
            paginatedData.map(card => (
              <div 
                key={card.userCardId || `${card.githubUsername}-${Math.random()}`} 
                onClick={() => setSelectedCard(card)} 
                className="cursor-pointer flex justify-center w-full"
              >
                 <Card
                   {...card}
                   quantity={1 + (card.shards || 0)}
                   disableLink={true}
                   loyaltyTier={card.loyaltyTier}
                   loyaltyCount={card.loyaltyCount}
                 />
              </div>
            ))
          )}
        </div>
      )}

      {/* 4. Large Card Modal with Loyalty Details */}
      {selectedCard && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-md p-4 overflow-y-auto" onClick={() => setSelectedCard(null)}>
          <div className="relative flex flex-col md:flex-row items-center md:items-start justify-center gap-6 w-full max-w-5xl my-auto" onClick={e => e.stopPropagation()}>
             <button 
               onClick={() => setSelectedCard(null)}
               className="absolute -top-2 right-0 md:-right-12 text-slate-400 hover:text-white transition-colors bg-black/50 p-2 rounded-full border border-slate-700 z-10"
             >
               <X size={24} />
             </button>

             <div className="flex flex-col items-center flex-shrink-0 mt-4 md:mt-0 xl:mr-8 origin-top">
               <div className="pointer-events-none scale-90 sm:scale-100 xl:scale-110 origin-top mb-2 sm:mb-4 xl:mb-12">
                 <Card
                   {...selectedCard}
                   quantity={1 + (selectedCard.shards || 0)}
                   disableLink={true}
                   loyaltyTier={selectedCard.loyaltyTier}
                   loyaltyCount={selectedCard.loyaltyCount}
                 />
               </div>

               {/* Buttons below the card */}
               <div className="flex flex-row gap-3 items-center justify-center w-full max-w-[280px] relative z-20">
                 <a 
                   href={`https://github.com/${selectedCard.githubUsername}`}
                   target="_blank"
                   rel="noopener noreferrer"
                   className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl shadow-[0_0_15px_rgba(79,70,229,0.3)] transition-all hover:scale-105 text-sm"
                 >
                   <GithubLogo size={18} weight="fill" />
                   Open Profile
                 </a>

                 {selectedCard.stamina !== undefined && calculateCurrentStamina(selectedCard.stamina, selectedCard.lastUsedAt ? new Date(selectedCard.lastUsedAt) : new Date(), selectedCard.inActiveTeam || false) < 100 && (
                   <button
                     onClick={() => handleRecoverStamina(selectedCard)}
                     disabled={recovering}
                     className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 bg-gradient-to-r from-emerald-500 to-emerald-600 hover:from-emerald-400 hover:to-emerald-500 text-white font-bold rounded-xl shadow-[0_0_15px_rgba(16,185,129,0.3)] transition-all hover:scale-105 text-sm disabled:opacity-50 disabled:hover:scale-100"
                   >
                     <Lightning size={18} weight="fill" />
                     {recovering ? 'Recovering...' : 'Cure (100)'}
                   </button>
                 )}
               </div>
             </div>

             {/* Loyalty Progress Section */}
             <div className="w-full max-w-md bg-slate-900 border border-slate-700 rounded-2xl p-6 shadow-2xl space-y-4">
               <div className="flex items-center justify-between">
                 <h3 className="text-sm font-bold text-white flex items-center gap-2">
                   <Fire size={16} weight="fill" className="text-orange-400" />
                   Loyalty Contract
                 </h3>
                 <LoyaltyBadge tier={selectedCard.loyaltyTier || 'none'} size="md" />
               </div>
               <LoyaltyProgressBar count={selectedCard.loyaltyCount || 0} tier={selectedCard.loyaltyTier || 'none'} />

               {/* Milestone History */}
               <div className="space-y-2 mt-4">
                 <p className="text-[10px] uppercase tracking-widest text-slate-500 font-bold">Milestones</p>
                 {MILESTONE_ORDER.map(tier => {
                   const info = LOYALTY_TIERS[tier];
                   const milestones = (selectedCard.loyaltyMilestones || []) as any[];
                   const completed = milestones.find((m: any) => m.tier === tier);
                   const battlesRemaining = Math.max(0, info.threshold - (selectedCard.loyaltyCount || 0));

                   return (
                     <div
                       key={tier}
                       className={clsx(
                         'flex items-center gap-3 px-3 py-2 rounded-lg border text-xs',
                         completed
                           ? 'border-white/10 bg-white/5'
                           : 'border-slate-800 bg-slate-950/50 opacity-60'
                       )}
                     >
                       <span className="text-sm">{info.icon}</span>
                       <div className="flex-1 min-w-0">
                         <p className="font-bold" style={{ color: completed ? info.color : '#64748b' }}>
                           {info.title}
                           <span className="text-slate-500 font-normal ml-1">({info.threshold} battles)</span>
                         </p>
                         <p className="text-[10px] text-slate-500">
                           +{info.atkDefBonus}% ATK/DEF{info.hpBonus > 0 ? `, +${info.hpBonus}% HP` : ''}
                         </p>
                       </div>
                       <div className="text-right flex-shrink-0">
                         {completed ? (
                           <span className="text-[10px] text-green-400 font-bold">
                             ✓ {new Date(completed.unlockedAt).toLocaleDateString()}
                           </span>
                         ) : (
                           <span className="text-[10px] text-slate-500 font-mono">
                             {battlesRemaining} left
                           </span>
                         )}
                       </div>
                     </div>
                   );
                 })}
               </div>

               {/* Lifetime Stats */}
               {selectedCard.lifetimeStats && (
                 <div className="mt-3 pt-3 border-t border-slate-800">
                   <p className="text-[9px] uppercase tracking-widest text-slate-500 font-bold mb-2">Lifetime Stats</p>
                   <div className="grid grid-cols-2 gap-2">
                     <div className="bg-slate-950/50 border border-slate-800 rounded-lg p-2 text-center">
                       <p className="text-lg font-black text-red-400">{(selectedCard.lifetimeStats.damageDealt || 0).toLocaleString()}</p>
                       <p className="text-[9px] text-slate-500 uppercase">Damage Dealt</p>
                     </div>
                     <div className="bg-slate-950/50 border border-slate-800 rounded-lg p-2 text-center">
                       <p className="text-lg font-black text-emerald-400">{selectedCard.lifetimeStats.battlesWon || 0}</p>
                       <p className="text-[9px] text-slate-500 uppercase">Battles Won</p>
                     </div>
                     <div className="bg-slate-950/50 border border-slate-800 rounded-lg p-2 text-center">
                       <p className="text-lg font-black text-yellow-400">{selectedCard.lifetimeStats.critsLanded || 0}</p>
                       <p className="text-[9px] text-slate-500 uppercase">Crits Landed</p>
                     </div>
                     <div className="bg-slate-950/50 border border-slate-800 rounded-lg p-2 text-center">
                       <p className="text-lg font-black text-purple-400">{selectedCard.lifetimeStats.passivesTriggered || 0}</p>
                       <p className="text-[9px] text-slate-500 uppercase">Passives Used</p>
                     </div>
                   </div>
                 </div>
               )}
             </div>
          </div>
        </div>
      )}

    </div>
  );
}

const raritiesConfig = {
  'L': { label: 'Legendary', color: '#ffd700' },
  'E': { label: 'Epic', color: '#a855f7' },
  'R': { label: 'Rare', color: '#3b82f6' },
  'U': { label: 'Uncommon', color: '#22c55e' },
  'C': { label: 'Common', color: '#94a3b8' }
};

import { getCurrentUser } from '@/lib/session';
import { prisma } from '@/lib/prisma';
import { redirect } from 'next/navigation';
import CollectionClient from './CollectionClient';

export default async function CollectionPage() {
  const user = await getCurrentUser();
  if (!user) {
    redirect('/');
  }

  const userCards = await prisma.userCard.findMany({
    where: { userId: user.id },
    include: { card: true },
    orderBy: { card: { atk: 'desc' } }
  });

  const cardsList = userCards.map(uc => ({
    id: uc.card.id,
    userCardId: uc.id,
    name: uc.card.name,
    githubUsername: uc.card.githubUsername,
    avatarUrl: uc.card.avatarUrl || '',
    flavorText: uc.card.flavorText,
    atk: uc.card.atk,
    def: uc.card.def,
    hp: uc.card.hp,
    rarity: uc.card.rarity,
    primaryLanguage: uc.card.primaryLanguage || 'Unknown',
    quantity: uc.quantity,
    shards: uc.shards,
    isShiny: uc.isShiny,
    stamina: uc.stamina,
    lastUsedAt: uc.lastUsedAt,
    inActiveTeam: uc.inActiveTeam,
    loyaltyCount: uc.loyaltyCount,
    loyaltyTier: uc.loyaltyTier,
    loyaltyMilestones: uc.loyaltyMilestones as any[],
    lifetimeStats: uc.lifetimeStats as any,
    showcaseOrder: uc.showcaseOrder,
  }));

  return <CollectionClient initialCards={cardsList} />;
}

'use client';

import React, { useState, useEffect } from 'react';
import { Card } from '@/components/Card';
import { useSession } from 'next-auth/react';
import { MagnifyingGlass, ClockCounterClockwise, Star, Sparkle, Hammer, Coin, BookOpenText } from '@phosphor-icons/react';
import { toast, Toaster } from 'react-hot-toast';

type FragmentWallet = Record<string, number>;
type WishlistItem = {
  username: string;
  name: string;
  avatarUrl: string;
  primaryLanguage: string;
  rarity: string;
  fragmentsRequired: number;
};
type FragmentLog = {
  date: string;
  source: string;
  language: string;
  amount: number;
};

// Common icons/colors for languages
const LANG_COLORS: Record<string, string> = {
  JavaScript: 'bg-yellow-400 text-yellow-900 border-yellow-500',
  TypeScript: 'bg-blue-500 text-white border-blue-600',
  Python: 'bg-blue-400 text-white border-yellow-300',
  Rust: 'bg-orange-600 text-white border-orange-700',
  Go: 'bg-cyan-400 text-cyan-950 border-cyan-500',
  Ruby: 'bg-red-500 text-white border-red-600',
  'C++': 'bg-indigo-600 text-white border-indigo-700',
  CSS: 'bg-pink-500 text-white border-pink-600',
  HTML: 'bg-orange-500 text-white border-orange-600',
  Java: 'bg-red-600 text-white border-orange-500',
  PHP: 'bg-indigo-400 text-white border-purple-500',
  Unknown: 'bg-slate-600 text-white border-slate-700'
};

export default function ForgeClient() {
  const { data: session } = useSession();
  const [activeTab, setActiveTab] = useState<'INVOKE' | 'WISHLIST' | 'HISTORY'>('INVOKE');

  const [fragments, setFragments] = useState<FragmentWallet>({});
  const [logs, setLogs] = useState<FragmentLog[]>([]);
  const [wishlist, setWishlist] = useState<WishlistItem[]>([]);
  const [currency, setCurrency] = useState(0);

  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [searchResult, setSearchResult] = useState<any>(null);

  const [isInvoking, setIsInvoking] = useState(false);
  const [revealedCard, setRevealedCard] = useState<any>(null);

  useEffect(() => {
    fetchWallet();
  }, []);

  const fetchWallet = async () => {
    try {
      const res = await fetch('/api/forge/wallet');
      if (res.ok) {
        const data = await res.json();
        setFragments(data.fragments || {});
        setLogs(data.fragmentLogs || []);
        setWishlist(data.wishlist || []);
        setCurrency(data.currency || 0);
      }
    } catch (e) {
      console.error(e);
    }
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    setIsSearching(true);
    setSearchResult(null);
    setRevealedCard(null);

    try {
      const res = await fetch(`/api/forge/search?username=${encodeURIComponent(searchQuery)}`);
      const data = await res.json();
      if (res.ok) {
        setSearchResult(data);
      } else {
        toast.error(data.error || 'Developer not found');
      }
    } catch (e) {
      toast.error('Search failed');
    } finally {
      setIsSearching(false);
    }
  };

  const handleInvoke = async () => {
    if (!searchResult) return;
    setIsInvoking(true);
    try {
      const res = await fetch('/api/forge/invoke', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username: searchResult.stats.githubUsername })
      });
      const data = await res.json();
      if (res.ok) {
        setRevealedCard(data.card);
        fetchWallet(); // Refresh balances
        toast.success(`Successfully invoked ${data.card.name}!`);
      } else {
        toast.error(data.error || 'Invocation failed');
      }
    } catch (e) {
      toast.error('Invocation failed');
    } finally {
      setIsInvoking(false);
    }
  };

  const toggleWishlist = async (username: string) => {
    const isWished = wishlist.some(w => w.username.toLowerCase() === username.toLowerCase());
    try {
      let res;
      if (isWished) {
        res = await fetch(`/api/forge/wishlist?username=${encodeURIComponent(username)}`, { method: 'DELETE' });
      } else {
        res = await fetch('/api/forge/wishlist', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ username })
        });
      }

      const data = await res.json();
      if (res.ok) {
        setWishlist(data.wishlist);
        toast.success(isWished ? 'Removed from Wishlist' : 'Added to Wishlist');
      } else {
        toast.error(data.error || 'Wishlist update failed');
      }
    } catch (e) {
      toast.error('Wishlist update failed');
    }
  };

  // Derived state for invoke button
  const reqFragments = searchResult?.cost?.fragments || 0;
  const reqBits = searchResult?.cost?.bits || 0;
  const lang = searchResult?.stats?.primaryLanguage || 'Unknown';
  const ownedFragments = fragments[lang] || 0;

  const hasFragments = ownedFragments >= reqFragments;
  const hasBits = currency >= reqBits;
  const canInvoke = hasFragments && hasBits;

  // Wallet Badges
  const renderWallet = () => {
    const activeFragments = Object.entries(fragments).filter(([_, count]) => count > 0);

    if (activeFragments.length === 0) return <div className="text-slate-500 text-sm">No fragments yet. Open packs to find some!</div>;

    return (
      <div className="flex flex-wrap gap-2">
        {activeFragments.map(([l, count]) => {
          const colorClass = LANG_COLORS[l] || LANG_COLORS.Unknown;
          return (
            <div key={l} className={`px-3 py-1 rounded-full text-xs font-bold border flex items-center gap-2 ${colorClass} shadow-md`}>
              <span>{l}</span>
              <span className="bg-black/20 px-1.5 rounded">{count}</span>
            </div>
          );
        })}
      </div>
    );
  };

  // Reveal screen
  if (revealedCard) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in fade-in zoom-in duration-500">
        <Toaster position="top-center" />
        <h2 className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-amber-600 mb-8 drop-shadow-[0_0_15px_rgba(252,211,77,0.5)]">
          Invocation Successful!
        </h2>
        <div className="scale-125 mb-12 relative group">
          <div className="absolute inset-0 bg-yellow-400/20 blur-3xl rounded-full scale-150 animate-pulse"></div>
          <Card {...revealedCard} disableLink />
        </div>
        <button 
          onClick={() => { setRevealedCard(null); setSearchResult(null); setSearchQuery(''); }}
