            required
            minLength={6}
          />

          <button
            type="submit"
            disabled={loading}
            className="w-full px-4 py-3 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-600 text-white font-bold tracking-wide hover:from-indigo-400 hover:to-purple-500 transition-all disabled:opacity-50"
          >
            {loading ? 'Processing...' : (isRegistering ? 'Sign Up' : 'Sign In')}
          </button>
        </form>

        <p className="mt-6 text-center text-sm text-slate-400">
          {isRegistering ? 'Already have an account? ' : 'New to GitGacha? '}
          <button 
            type="button" 
            onClick={() => setIsRegistering(!isRegistering)}
            className="text-indigo-400 hover:text-indigo-300 font-bold underline"
          >
            {isRegistering ? 'Sign In' : 'Create Account'}
          </button>
        </p>

      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useSession } from 'next-auth/react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { 
  Trophy, Shield, Sword, Heart, UserPlus, 
  Users, UserMinus, UserCheck, Star, Envelope,
  Sparkle, ShieldCheck, Fire, Plus, Clock
} from '@phosphor-icons/react';
import { Navbar } from '@/components/Navbar';
import { getXPProgress } from '@/lib/xpService';
import { Card } from '@/components/Card';

interface FriendInfo {
  id: string;
  username: string;
  level: number;
}

interface ProfileData {
  user: {
    id: string;
    username: string;
    level: number;
    xp: number;
    rating: number;
    createdAt: string;
  };
  stats: {
    totalCards: number;
    battlesWon: number;
    battlesLost: number;
    totalBattles: number;
    friendsCount: number;
  };
  topCards: any[];
  friends: FriendInfo[];
  hasLeveledUpRecently: boolean;
  hasLegendaryBondPrestige: boolean;
  showcaseCards: any[];
}

export default function ProfilePage() {
  const { data: session } = useSession();
  const params = useParams();
  const profileUsername = decodeURIComponent(params.username as string);

  const [profile, setProfile] = useState<ProfileData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [friendStatus, setFriendStatus] = useState<'NONE' | 'PENDING' | 'FRIENDS'>('NONE');
  const [friendshipId, setFriendshipId] = useState<string | null>(null);

  useEffect(() => {
    fetchProfile();
    if (session?.user?.email && profileUsername !== session.user.name) {
      checkFriendStatus();
    }
  }, [profileUsername, session]);

  const fetchProfile = async () => {
    try {
      const res = await fetch(`/api/profile/${profileUsername}`);
      const data = await res.json();
      if (res.ok) {
        setProfile(data);
      } else {
        setError(data.error);
      }
    } catch (err) {
      setError('Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const checkFriendStatus = async () => {
    try {
      const res = await fetch('/api/friends');
      const data = await res.json();

      if (res.ok) {
        const isFriend = data.friends.find((f: any) => f.user.username === profileUsername);
        if (isFriend) {
          setFriendStatus('FRIENDS');
          setFriendshipId(isFriend.friendshipId);
          return;
        }

        const isOutgoing = data.outgoingRequests.find((r: any) => r.user.username === profileUsername);
        if (isOutgoing) {
          setFriendStatus('PENDING');
          setFriendshipId(isOutgoing.id);
          return;
        }

        // We aren't checking incoming here but could. Simple checking for now.
        setFriendStatus('NONE');
      }
    } catch (err) {
      console.error('Failed to check friend status', err);
    }
  };

  const handleAddFriend = async () => {
    try {
      const res = await fetch('/api/friends/request', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ targetUsername: profileUsername })
      });
      if (res.ok) {
        setFriendStatus('PENDING');
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleRemoveFriend = async () => {
    if (!friendshipId) return;
    try {
      const res = await fetch('/api/friends/remove', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ friendshipId })
      });
      if (res.ok) {
        setFriendStatus('NONE');
        setFriendshipId(null);
      }
    } catch (err) {
      console.error(err);
    }
  };

  const isOwnProfile = (session?.user as any)?.username === profileUsername || session?.user?.name === profileUsername;

  if (loading) return (
