const SECTIONS = [
  { id: 'getting-started', title: 'Getting Started' },
  { id: 'cards-and-rarities', title: 'Cards and Rarities' },
  { id: 'stats-explained', title: 'Stats Explained' },
  { id: 'language-types', title: 'Language Types and Advantages' },
