import { getLoyaltyBonuses } from './loyaltyService';

export type CardType = 'Python' | 'JavaScript' | 'Ruby' | 'PHP' | 'Rust' | 'C' | 'C++' | 'Go' | 'TypeScript' | 'CSS' | 'Neutral' | 'Legendary';
export type Rarity = 'Common' | 'Uncommon' | 'Rare' | 'Epic' | 'Legendary';

export interface BattleCard {
  id: string; // This will map to UserCard.id in practice for user cards, or Card.id for random defenders
  name: string;
  atk: number;
  def: number;
  hp: number;
  maxHp: number;
  stamina: number;
  rarity: Rarity;
  primaryLanguage: string | null;
  type: CardType;
  avatarUrl?: string | null;
  loyaltyTier?: string;

  // Momentum & Tracking
  consecutiveWins?: number;
  momentumStacks?: number;
  statsDealtDamage?: number;
  statsTakenDamage?: number;
  statsPassivesTriggered?: number;
  statsCritsLanded?: number;
  statsMomentumAchieved?: boolean;
}

export interface BattleLogEvent {
  type: 'damage' | 'passive' | 'synergy' | 'defeat' | 'type_advantage' | 'enter_field' | 'draw' | 'battle_start' | 'battle_end';
  cardId?: string;
  targetId?: string;
  value?: number;
  message: string;
}

export interface TurnLog {
  turnNumber: number;
  cCardId: string;
  dCardId: string;
  cHpStart: number;
  dHpStart: number;
  cHpEnd: number;
  dHpEnd: number;
  events: BattleLogEvent[];
}

export interface BattleResult {
  winner: 'CHALLENGER' | 'DEFENDER';
  log: TurnLog[];
  challengerTeamState: BattleCard[];
  defenderTeamState: BattleCard[];
}

// ---------------------------------------------------------
// Helpers
// ---------------------------------------------------------

export function getCardType(card: any): CardType {
  if (card.rarity === 'Legendary' && card.pack === 'GitHub OGs') {
    return 'Legendary';
  }
  const lang = card.primaryLanguage;
  if (!lang) return 'Neutral';

  if (lang === 'Python' || lang === 'JavaScript' || lang === 'Ruby' || lang === 'PHP' || lang === 'Rust' || lang === 'C' || lang === 'C++' || lang === 'Go' || lang === 'TypeScript' || lang === 'CSS') {
    return lang as CardType;
  }
  return 'Neutral';
}

function getRarityMultiplier(rarity: string): number {
  switch (rarity) {
    case 'Common': return 0.6;   // -40%
    case 'Uncommon': return 0.8; // -20%
    case 'Rare': return 1.0;     // Base
    case 'Epic': return 1.2;     // +20%
    case 'Legendary': return 1.4;// +40%
    default: return 1.0;
  }
}

// ---------------------------------------------------------
// Type Matchups (1.5x / 0.75x)
// ---------------------------------------------------------
function getTypeMultiplier(attackerType: CardType, defenderType: CardType): number {
  const advantages: Record<string, string[]> = {
    'Python': ['JavaScript'],
    'JavaScript': ['Ruby'],
    'Ruby': ['PHP'],
    'PHP': ['Python'],
    'Rust': ['C', 'C++'],
    'C': ['Go'],
    'C++': ['Go'],
    'Go': ['Rust'],
    'TypeScript': ['JavaScript']
  };

  // CSS loses to every type (deals 0.75x except vs CSS/Legendary/Neutral)
  if (attackerType === 'CSS') {
    if (defenderType !== 'CSS' && defenderType !== 'Legendary' && defenderType !== 'Neutral') {
      return 0.75;
    }
    return 1.0;
  }

  if (advantages[attackerType] && advantages[attackerType].includes(defenderType)) {
    return 1.5;
  }

  // Reverse: check if attacker is at a type disadvantage
  let isDisadvantage = false;
  Object.keys(advantages).forEach(t => {
    if (advantages[t].includes(attackerType as string) && t === (defenderType as string)) {
      isDisadvantage = true;
    }
  });

  if (isDisadvantage) return 0.75;

  return 1.0;
}

// ---------------------------------------------------------
// Core Resolver Function
// ---------------------------------------------------------
export function resolve3v3Battle(cTeamInitial: BattleCard[], dTeamInitial: BattleCard[]): BattleResult {
  // Deep copy teams
  const cTeam = JSON.parse(JSON.stringify(cTeamInitial)) as BattleCard[];
  const dTeam = JSON.parse(JSON.stringify(dTeamInitial)) as BattleCard[];

  // Apply loyalty bonuses FIRST (permanent multiplier on base stats)
  const applyLoyaltyBonuses = (team: BattleCard[]) => {
    team.forEach(c => {
      const bonuses = getLoyaltyBonuses(c.loyaltyTier || 'none');
      c.atk = Math.floor(c.atk * bonuses.atkMult);
      c.def = Math.floor(c.def * bonuses.defMult);
      c.hp = Math.floor(c.hp * bonuses.hpMult);
      c.maxHp = Math.floor(c.maxHp * bonuses.hpMult);
    });
  };

  applyLoyaltyBonuses(cTeam);
  applyLoyaltyBonuses(dTeam);

  // Apply stamina penalty to ATK and DEF (after loyalty)
  const applyStaminaPenalty = (team: BattleCard[]) => {
    team.forEach(c => {
      let multiplier = 1.0;
      if (c.stamina <= 20) multiplier = 0.40;
      else if (c.stamina <= 40) multiplier = 0.60;
      else if (c.stamina <= 60) multiplier = 0.75;
      else if (c.stamina <= 80) multiplier = 0.90;

      c.atk = Math.floor(c.atk * multiplier);
      c.def = Math.floor(c.def * multiplier);
    });
  };

  applyStaminaPenalty(cTeam);
  applyStaminaPenalty(dTeam);

  const log: TurnLog[] = [];
  let turnNumber = 1;

  let cIdx = 0;
  let dIdx = 0;

  // Synergies initialization
  const applySynergies = (team: BattleCard[], isChallenger: boolean) => {
    const events: BattleLogEvent[] = [];
    const typeCounts: Record<string, number> = {};
    team.forEach(c => {
      typeCounts[c.type] = (typeCounts[c.type] || 0) + 1;
    });

    // Check mixed team (all 3 unique)
    if (Object.keys(typeCounts).length === 3) {
      team.forEach(c => c.atk = Math.floor(c.atk * 1.08));
      events.push({ type: 'synergy', message: `${isChallenger ? 'Challenger' : 'Defender'} Mixed Team synergy! +8% ATK to all.` });
    }

    // Check pairs/triples
    Object.keys(typeCounts).forEach(type => {
      if (typeCounts[type] >= 2) {
        const mult = typeCounts[type] === 3 ? 2 : 1;
        events.push({ type: 'synergy', message: `${isChallenger ? 'Challenger' : 'Defender'} ${type} Synergy (x${typeCounts[type]}) activated!` });
        // Specific synergy effects will be handled during turns, but we can store markers on the cards
        if (type === 'Python') {
            team.forEach(c => (c as any).pySynergy = 0.03 * mult);
        }
        if (type === 'Rust') {
            team.forEach(c => (c as any).rustSynergy = 0.10 * mult);
        }
        if (type === 'JavaScript') {
            team.forEach(c => (c as any).jsSynergy = 0.10 * mult);
        }
        if (type === 'Go') {
            team.forEach(c => (c as any).goSynergy = true); // Handled on Enter
        }
      }
    });

    // Big Tech + Indie Hacker synergy - skip for now or implement if you add "pack" to card model.

    return events;
  };

  const startEvents = [
    { type: 'battle_start' as const, message: 'Battle Started!' },
    ...applySynergies(cTeam, true),
    ...applySynergies(dTeam, false)
  ];

  log.push({
      turnNumber: 0,
      cCardId: '', dCardId: '', cHpStart: 0, dHpStart: 0, cHpEnd: 0, dHpEnd: 0,
      events: startEvents
  });

  const enterField = (card: BattleCard, opponent: BattleCard, logEvents: BattleLogEvent[]) => {
      logEvents.push({ type: 'enter_field', cardId: card.id, message: `${card.name} enters the field!` });

      // Rust Iron Shield
      if (card.type === 'Rust') {
          (card as any).ironShieldActive = true;
          logEvents.push({ type: 'passive', cardId: card.id, message: `[Rust] ${card.name} gained Iron Shield (blocks first turn damage).` });
      }

      // Go First Strike OR Go Synergy First Strike
      if (card.type === 'Go' || (card as any).goSynergy) {
          logEvents.push({ type: 'passive', cardId: card.id, message: `${card.name} strikes first on entry!` });
          let dmg = Math.floor(Math.max(card.atk * 0.15, card.atk - opponent.def * 0.25));
          if (dmg < 1) dmg = 1;

          if ((opponent as any).ironShieldActive) {
            dmg = 0;
            (opponent as any).ironShieldActive = false; // consume it? Or does it block the whole FIRST TURN? "absorbs the first full turn of damage completely, taking zero damage that turn only." 
            logEvents.push({ type: 'passive', cardId: opponent.id, message: `Iron Shield blocked First Strike!` });
          } else {
             opponent.hp -= dmg;
             logEvents.push({ type: 'damage', cardId: card.id, targetId: opponent.id, value: dmg, message: `${card.name} dealt ${dmg} first strike damage.` })
          }
      }
  };

  let cJustEntered = true;
  let dJustEntered = true;
  let turnsInMatchup = 0;

  while (cIdx < 3 && dIdx < 3) {
    const cCard = cTeam[cIdx];
    const dCard = dTeam[dIdx];

    const turnEvents: BattleLogEvent[] = [];

    if (cJustEntered) enterField(cCard, dCard, turnEvents);
    if (dJustEntered && dCard.hp > 0) enterField(dCard, cCard, turnEvents); // Only if dCard didn't die from cCard's first strike

    cJustEntered = false;
    dJustEntered = false;

    if (cCard.hp <= 0 || dCard.hp <= 0) {
        // Someone died from first strike
        if (cCard.hp <= 0) {
            turnEvents.push({ type: 'defeat', cardId: cCard.id, message: `${cCard.name} was defeated!` });
            cIdx++; cJustEntered = true; turnsInMatchup = 0;

            dCard.consecutiveWins = (dCard.consecutiveWins || 0) + 1;
            if (dCard.consecutiveWins >= 2) {
               const newStacks = Math.min(3, dCard.consecutiveWins - 1);
               if ((dCard.momentumStacks || 0) < newStacks) {
                   dCard.momentumStacks = newStacks;
                   dCard.statsMomentumAchieved = true;
                   turnEvents.push({ type: 'passive', cardId: dCard.id, message: `${dCard.name} is On Fire! (+${newStacks * 10}% Stats)` });
               }
            }
        }
        if (dCard.hp <= 0) {
            turnEvents.push({ type: 'defeat', cardId: dCard.id, message: `${dCard.name} was defeated!` });
            dIdx++; dJustEntered = true; turnsInMatchup = 0;

            if (cCard.hp > 0) {
                cCard.consecutiveWins = (cCard.consecutiveWins || 0) + 1;
                if (cCard.consecutiveWins >= 2) {
                   const newStacks = Math.min(3, cCard.consecutiveWins - 1);
                   if ((cCard.momentumStacks || 0) < newStacks) {
                       cCard.momentumStacks = newStacks;
                       cCard.statsMomentumAchieved = true;
                       turnEvents.push({ type: 'passive', cardId: cCard.id, message: `${cCard.name} is On Fire! (+${newStacks * 10}% Stats)` });
                   }
                }
            }
        }
        log.push({
            turnNumber, cCardId: cCard.id, dCardId: dCard.id,
            cHpStart: cCard.hp, dHpStart: dCard.hp, cHpEnd: Math.max(0, cCard.hp), dHpEnd: Math.max(0, dCard.hp),
            events: turnEvents
        });
        turnNumber++;
        continue;
    }

    const cHpStart = cCard.hp;
    const dHpStart = dCard.hp;

    // --- Damage Calculation ---
    // Type Multipliers
    let cTypeMult = getTypeMultiplier(cCard.type, dCard.type);
    let dTypeMult = getTypeMultiplier(dCard.type, cCard.type);

    if (cTypeMult > 1) turnEvents.push({ type: 'type_advantage', cardId: cCard.id, message: `${cCard.name} has Type Advantage!` });
    if (dTypeMult > 1) turnEvents.push({ type: 'type_advantage', cardId: dCard.id, message: `${dCard.name} has Type Advantage!` });

    // CSS Passive (20% Double Damage, or Undefined Behavior)
    const cRarityMult = getRarityMultiplier(cCard.rarity);
    const dRarityMult = getRarityMultiplier(dCard.rarity);

    let cAtkBonus = 1;
    let dAtkBonus = 1;

    let cZeroDmg = false;
    let dZeroDmg = false;

    // CSS Undefined Behavior
    if (cCard.type === 'CSS') {
        if (Math.random() < 0.25 * cRarityMult) {
            cAtkBonus = 2;
            turnEvents.push({ type: 'passive', cardId: cCard.id, message: `[CSS] ${cCard.name} double damage!` });
        } else if (Math.random() < 0.15 * cRarityMult) {
            cZeroDmg = true;
            turnEvents.push({ type: 'passive', cardId: cCard.id, message: `[CSS] ${cCard.name} undefined behavior (0 damage)!` });
        }
    }
    if (dCard.type === 'CSS') {
        if (Math.random() < 0.25 * dRarityMult) {
            dAtkBonus = 2;
            turnEvents.push({ type: 'passive', cardId: dCard.id, message: `[CSS] ${dCard.name} double damage!` });
        } else if (Math.random() < 0.15 * dRarityMult) {
            dZeroDmg = true;
            turnEvents.push({ type: 'passive', cardId: dCard.id, message: `[CSS] ${dCard.name} undefined behavior (0 damage)!` });
        }
    }

    // Ruby Last Stand
    if (cCard.type === 'Ruby' && cCard.hp < cCard.maxHp * 0.3) {
        cAtkBonus *= 1.35;
        turnEvents.push({ type: 'passive', cardId: cCard.id, message: `[Ruby] Last stand active!` });
    }
    if (dCard.type === 'Ruby' && dCard.hp < dCard.maxHp * 0.3) {
        dAtkBonus *= 1.35;
        turnEvents.push({ type: 'passive', cardId: dCard.id, message: `[Ruby] Last stand active!` });
    }

    // C/C++ Raw Power (Ignore 50% DEF)
    let dDefEffective = dCard.def;
    let cDefEffective = cCard.def;

    if (cCard.type === 'C' || cCard.type === 'C++') dDefEffective *= 0.5;
    if (dCard.type === 'C' || dCard.type === 'C++') cDefEffective *= 0.5;

    // TypeScript Type Safety (-15% damage taken)
    let cDmgReceivedMult = cCard.type === 'TypeScript' ? 0.85 : 1;
    let dDmgReceivedMult = dCard.type === 'TypeScript' ? 0.85 : 1;

    // Rust Synergy (-10% damage taken)
    if ((cCard as any).rustSynergy) cDmgReceivedMult -= (cCard as any).rustSynergy;
    if ((dCard as any).rustSynergy) dDmgReceivedMult -= (dCard as any).rustSynergy;

    // Base damage formula with Momentum
    let cBaseAtk = cCard.atk * cAtkBonus * cTypeMult * (1 + (cCard.momentumStacks || 0) * 0.1);
    let dBaseAtk = dCard.atk * dAtkBonus * dTypeMult * (1 + (dCard.momentumStacks || 0) * 0.1);

    // Effective DEF with Momentum
    let cDefMom = cDefEffective * (1 + (cCard.momentumStacks || 0) * 0.1);
    let dDefMom = dDefEffective * (1 + (dCard.momentumStacks || 0) * 0.1);

    let cDmgToD = Math.floor(Math.max(cBaseAtk * 0.15, cBaseAtk - (dDefMom * 0.25)));
    let dDmgToC = Math.floor(Math.max(dBaseAtk * 0.15, dBaseAtk - (cDefMom * 0.25)));

    if (cDmgToD < 1) cDmgToD = 1;
    if (dDmgToC < 1) dDmgToC = 1;

    if (cZeroDmg) cDmgToD = 0;
    if (dZeroDmg) dDmgToC = 0;

    // JS double callback
    if (cCard.type === 'JavaScript' || (cCard as any).jsSynergy) {
        const chance = cCard.type === 'JavaScript' ? 0.25 * cRarityMult : (cCard as any).jsSynergy;
        if (Math.random() < chance) {
            turnEvents.push({ type: 'passive', cardId: cCard.id, message: `[JS] Double Callback!` });
            cDmgToD += Math.floor(cDmgToD * 0.5);
        }
    }
    if (dCard.type === 'JavaScript' || (dCard as any).jsSynergy) {
        const chance = dCard.type === 'JavaScript' ? 0.25 * dRarityMult : (dCard as any).jsSynergy;
        if (Math.random() < chance) {
            turnEvents.push({ type: 'passive', cardId: dCard.id, message: `[JS] Double Callback!` });
            dDmgToC += Math.floor(dDmgToC * 0.5);
        }
    }

    // Apply Damage reduction multipliers
    cDmgToD = Math.floor(cDmgToD * dDmgReceivedMult);
    dDmgToC = Math.floor(dDmgToC * cDmgReceivedMult);

    // Rust Iron Shield turn 1 block
    if ((cCard as any).ironShieldActive) {
        dDmgToC = 0;
        (cCard as any).ironShieldActive = false; // consumed
        turnEvents.push({ type: 'passive', cardId: cCard.id, message: `Iron Shield blocked all damage!` });
    }
    if ((dCard as any).ironShieldActive) {
        cDmgToD = 0;
        (dCard as any).ironShieldActive = false; // consumed
        turnEvents.push({ type: 'passive', cardId: dCard.id, message: `Iron Shield blocked all damage!` });
    }


    cCard.hp -= dDmgToC;
    dCard.hp -= cDmgToD;

    // Track stats
    cCard.statsTakenDamage = (cCard.statsTakenDamage || 0) + dDmgToC;
    dCard.statsTakenDamage = (dCard.statsTakenDamage || 0) + cDmgToD;
    cCard.statsDealtDamage = (cCard.statsDealtDamage || 0) + cDmgToD;
    dCard.statsDealtDamage = (dCard.statsDealtDamage || 0) + dDmgToC;

    if (cAtkBonus > 1) cCard.statsPassivesTriggered = (cCard.statsPassivesTriggered || 0) + 1;
    if (dAtkBonus > 1) dCard.statsPassivesTriggered = (dCard.statsPassivesTriggered || 0) + 1;

    if (cDmgToD > 0) turnEvents.push({ type: 'damage', cardId: cCard.id, targetId: dCard.id, value: cDmgToD, message: `${cCard.name} dealt ${cDmgToD} damage.` });
    if (dDmgToC > 0) turnEvents.push({ type: 'damage', cardId: dCard.id, targetId: cCard.id, value: dDmgToC, message: `${dCard.name} dealt ${dDmgToC} damage.` });

    // End of Turn Effects (Regen)
    if (cCard.hp > 0 && (cCard.type === 'Python' || (cCard as any).pySynergy)) {
        const healPct = cCard.type === 'Python' ? 0.1 : ((cCard as any).pySynergy * 2);
        const heal = Math.floor(cCard.atk * healPct);
        cCard.hp = Math.min(cCard.maxHp, cCard.hp + heal);
        turnEvents.push({ type: 'passive', cardId: cCard.id, message: `[Python] Regenerated ${heal} HP.` });
    }
    if (dCard.hp > 0 && (dCard.type === 'Python' || (dCard as any).pySynergy)) {
        const healPct = dCard.type === 'Python' ? 0.1 : ((dCard as any).pySynergy * 2);
        const heal = Math.floor(dCard.atk * healPct);
        dCard.hp = Math.min(dCard.maxHp, dCard.hp + heal);
        turnEvents.push({ type: 'passive', cardId: dCard.id, message: `[Python] Regenerated ${heal} HP.` });
    }

    // Defeats
    if (cCard.hp <= 0 && dCard.hp <= 0) {
        turnEvents.push({ type: 'draw', message: `Both ${cCard.name} and ${dCard.name} go down!` });
        cIdx++; cJustEntered = true; turnsInMatchup = 0;
        dIdx++; dJustEntered = true; turnsInMatchup = 0;
    } else if (cCard.hp <= 0) {
        turnEvents.push({ type: 'defeat', cardId: cCard.id, message: `${cCard.name} was defeated!` });
        cIdx++; cJustEntered = true; turnsInMatchup = 0;

        dCard.consecutiveWins = (dCard.consecutiveWins || 0) + 1;
        if (dCard.consecutiveWins >= 2) {
           const newStacks = Math.min(3, dCard.consecutiveWins - 1);
           if ((dCard.momentumStacks || 0) < newStacks) {
               dCard.momentumStacks = newStacks;
               dCard.statsMomentumAchieved = true;
               turnEvents.push({ type: 'passive', cardId: dCard.id, message: `${dCard.name} is On Fire! (+${newStacks * 10}% Stats)` });
           }
        }
    } else if (dCard.hp <= 0) {
        turnEvents.push({ type: 'defeat', cardId: dCard.id, message: `${dCard.name} was defeated!` });
        dIdx++; dJustEntered = true; turnsInMatchup = 0;

        cCard.consecutiveWins = (cCard.consecutiveWins || 0) + 1;
        if (cCard.consecutiveWins >= 2) {
           const newStacks = Math.min(3, cCard.consecutiveWins - 1);
           if ((cCard.momentumStacks || 0) < newStacks) {
               cCard.momentumStacks = newStacks;
               cCard.statsMomentumAchieved = true;
               turnEvents.push({ type: 'passive', cardId: cCard.id, message: `${cCard.name} is On Fire! (+${newStacks * 10}% Stats)` });
           }
        }
    }

    log.push({
      turnNumber,
      cCardId: cCard.id,
      dCardId: dCard.id,
      cHpStart,
      dHpStart,
      cHpEnd: Math.max(0, cCard.hp),
      dHpEnd: Math.max(0, dCard.hp),
      events: turnEvents
    });

    turnNumber++;
    turnsInMatchup++;

    // 50-turn cap per matchup ties breaker
    if (turnsInMatchup >= 50) {
        console.warn(`[BattleResolver] 50-turn cap reached between ${cCard.name} and ${dCard.name}!`);

        // Resolve by remaining HP percentage
        const cPct = cCard.hp / cCard.maxHp;
        const dPct = dCard.hp / dCard.maxHp;

        let tiebreakerEvents: BattleLogEvent[] = [
            { type: 'passive', message: `Turn cap reached! Resolving matchup by HP%...` }
        ];

        if (cPct > dPct) {
            dCard.hp = 0;
            tiebreakerEvents.push({ type: 'defeat', cardId: dCard.id, message: `${cCard.name} wins by HP advantage (${Math.floor(cPct*100)}% to ${Math.floor(dPct*100)}%)!` });
            dIdx++; dJustEntered = true; turnsInMatchup = 0;
        } else if (dPct > cPct) {
            cCard.hp = 0;
            tiebreakerEvents.push({ type: 'defeat', cardId: cCard.id, message: `${dCard.name} wins by HP advantage (${Math.floor(dPct*100)}% to ${Math.floor(cPct*100)}%)!` });
            cIdx++; cJustEntered = true; turnsInMatchup = 0;
        } else {
            // true tie
            cCard.hp = 0;
            dCard.hp = 0;
            tiebreakerEvents.push({ type: 'draw', message: `Exact HP% draw! Both go down!` });
            cIdx++; cJustEntered = true; turnsInMatchup = 0;
            dIdx++; dJustEntered = true; turnsInMatchup = 0;
        }

        log.push({
            turnNumber,
            cCardId: cCard.id,
            dCardId: dCard.id,
            cHpStart: cCard.hp,
            dHpStart: dCard.hp,
            cHpEnd: Math.max(0, cCard.hp),
            dHpEnd: Math.max(0, dCard.hp),
            events: tiebreakerEvents
        });
        turnNumber++;
    }

    // Failsafe wrapper to prevent infinite loops from 1 DMG minimums if HP gets incredibly high somehow (shouldn't realistically happen)
    if (turnNumber > 200) {
        log.push({ turnNumber, cCardId: cCard.id, dCardId: dCard.id, cHpStart: cCard.hp, dHpStart: dCard.hp, cHpEnd: 0, dHpEnd: 0, events: [{type: 'battle_end', message:'Turn Limit Reached!'}] });
        break;
    }
  }

  const winner = cIdx < 3 ? 'CHALLENGER' : 'DEFENDER';

  log.push({
      turnNumber: turnNumber,
      cCardId: '', dCardId: '', cHpStart: 0, dHpStart: 0, cHpEnd: 0, dHpEnd: 0,
      events: [{ type: 'battle_end', message: `${winner} WINS THE BATTLE!`}]
  });

  return {
    winner,
    log,
    challengerTeamState: cTeam,
    defenderTeamState: dTeam,
  };
}

import { prisma } from './prisma';
import { resolve3v3Battle, BattleCard, getCardType } from './battleResolver';
import { syncCardStamina } from './staminaService';
import { incrementLoyaltyAndCheck, updateLifetimeStats, MilestoneUnlock } from './loyaltyService';

const RARITY_ORDER: Record<string, number> = {
  Common: 1,
  Uncommon: 2,
  Rare: 3,
  Epic: 4,
  Legendary: 5,
};

// Calculate rewards based on win/loss, friend vs random, and rarity upset
// We use the AVERAGE rarity of the team now.
function getAverageRarityRank(team: BattleCard[]): number {
  if (team.length === 0) return 1;
  const sum = team.reduce((acc, card) => acc + (RARITY_ORDER[card.rarity] || 1), 0);
  return sum / team.length;
}

import { grantXP, XP_AMOUNTS } from './xpService';

export function calculateRewards(
  didWin: boolean,
  leagueMode: string,
  winnerAvgRank: number,
  loserAvgRank: number
): { bits: number; xp: number } {
  let bits: number;
  let xp: number;

  if (didWin) {
    switch (leagueMode) {
      case 'COMMON': bits = 80; xp = 100; break;
      case 'BALANCED': bits = 100; xp = 120; break;
      case 'DIVERSITY': bits = 120; xp = 140; break;
      case 'LEGENDARY': bits = 300; xp = 200; break;
      case 'OPEN':
      default: bits = 50; xp = 80; break;
    }
  } else {
    bits = 10;
    xp = 30; // 30 XP for loss regardless of league
  }

  return { bits, xp };
}

// Simple ELO rating update
export function calculateNewRatings(
  winnerRating: number,
  loserRating: number,
  K: number = 32
): { newWinnerRating: number; newLoserRating: number } {
  const expectedWinner = 1 / (1 + Math.pow(10, (loserRating - winnerRating) / 400));
  const expectedLoser = 1 - expectedWinner;

  const newWinnerRating = Math.round(winnerRating + K * (1 - expectedWinner));
  const newLoserRating = Math.max(0, Math.round(loserRating + K * (0 - expectedLoser)));

  return { newWinnerRating, newLoserRating };
}

export async function resolveRandomBattle(
  challengerId: string,
  challengerTeamCards: any[],
  leagueMode: string = 'OPEN'
) {
  // Map challenger info
  const cTeam: BattleCard[] = challengerTeamCards.map(c => ({
    id: c.id,
    name: c.name,
    atk: c.atk,
    def: c.def,
    hp: c.hp,
    maxHp: c.hp,
    stamina: c.stamina ?? 100,
    rarity: c.rarity as any,
    primaryLanguage: c.primaryLanguage,
    type: getCardType(c),
    avatarUrl: c.avatarUrl,
    loyaltyTier: c.loyaltyTier || 'none',
  }));

  const challengerAvgRank = getAverageRarityRank(cTeam);

  // Pick 3 random opponent cards from the DB, weighted somewhat by rarity (we can just fetch random from the pool for now, perhaps limiting top rarities if cTeam is weak, but for simplicity we fetch 3 random cards).
  const allCardsCount = await prisma.card.count();
  if (allCardsCount < 3) throw new Error('Not enough cards available for battle');

  // Fetch 3 random unique cards
  const randomSkip1 = Math.floor(Math.random() * (allCardsCount - 2));
  const dCardsRaw = await prisma.card.findMany({ skip: randomSkip1, take: 3 });

  // Sort them randomly
  const shuffledDCards = dCardsRaw.sort(() => 0.5 - Math.random());

  const dTeam: BattleCard[] = shuffledDCards.map(c => ({
    id: c.id,
    name: c.name,
    atk: c.atk,
    def: c.def,
    hp: c.hp,
    maxHp: c.hp,
    stamina: 100, // Random opponents start with 100 stamina
    rarity: c.rarity as any,
    primaryLanguage: c.primaryLanguage,
    type: getCardType(c),
    avatarUrl: c.avatarUrl,
  }));

  const defenderAvgRank = getAverageRarityRank(dTeam);

  // Run the battle!
  const battleResult = resolve3v3Battle(cTeam, dTeam);

  const playerWon = battleResult.winner === 'CHALLENGER';
  const rewards = calculateRewards(
    playerWon,
    leagueMode,
    playerWon ? challengerAvgRank : defenderAvgRank,
    playerWon ? defenderAvgRank : challengerAvgRank
  );

  // Create battle record
  const battle = await prisma.battle.create({
    data: {
      challengerId,
      defenderId: null,
      challengerTeam: cTeam as any, // initial state
      defenderTeam: dTeam as any, // initial state
      log: battleResult.log as any, // the turn-by-turn history
      status: 'COMPLETED',
      isRandom: true,
      leagueMode,
      battleStats: [
        ...battleResult.challengerTeamState,
        ...battleResult.defenderTeamState
      ].map(c => ({
        cardId: c.id,
        name: c.name,
        team: cTeam.some(ct => ct.id === c.id) ? 'CHALLENGER' : 'DEFENDER',
        damageDealt: c.statsDealtDamage || 0,
        damageReceived: c.statsTakenDamage || 0,
        passivesTriggered: c.statsPassivesTriggered || 0,
        critsLanded: c.statsCritsLanded || 0,
        momentumAchieved: !!c.statsMomentumAchieved
      })) as any,
      winnerId: playerWon ? challengerId : '__SYSTEM__',
      rewardBits: rewards.bits,
      completedAt: new Date(),
    }
  });

  // Grant rewards
  await prisma.user.update({
    where: { id: challengerId },
    data: {
      currency: { increment: rewards.bits },
      rating: {
          // Increase/decrease rating against a "reference" 1000 rating sys
          set: Math.max(0, calculateNewRatings(
              playerWon ? 1000 : 1000, 
              playerWon ? 1000 : 1000
          ).newWinnerRating) // For random battle it's a bit simple, let's just do a +5 / -5 for simplicity or use the elo
      }
    },
  });

  const xpResult = await grantXP(challengerId, rewards.xp);

  const userTemp = await prisma.user.findUnique({where: {id: challengerId}});
  if (userTemp) {
      const eloRes = calculateNewRatings(userTemp.rating, 1000);
      await prisma.user.update({
        where: { id: challengerId },
        data: {
          rating: playerWon ? eloRes.newWinnerRating : eloRes.newLoserRating
        }
    });
  }

  // Deduct 20 stamina from challenger cards
  const now = new Date();
  for (const c of challengerTeamCards) {
    await prisma.userCard.update({
      where: { id: c.id },
      data: {
        stamina: Math.max(0, c.stamina - 20),
        lastUsedAt: now,
      }
    }); // c.id is userCardId as mapped in api route
  }

  const battleStats = [
    ...battleResult.challengerTeamState,
    ...battleResult.defenderTeamState
  ].map(c => ({
    cardId: c.id,
    name: c.name,
    team: cTeam.some(ct => ct.id === c.id) ? 'CHALLENGER' : 'DEFENDER',
    damageDealt: c.statsDealtDamage || 0,
    damageReceived: c.statsTakenDamage || 0,
    passivesTriggered: c.statsPassivesTriggered || 0,
    critsLanded: c.statsCritsLanded || 0,
    momentumAchieved: !!c.statsMomentumAchieved,
  }));

  // --- Loyalty Processing for challenger cards ---
  const loyaltyUnlocks: { cardId: string; cardName: string; milestones: MilestoneUnlock[] }[] = [];
  for (const c of cTeam) {
    const unlocks = await incrementLoyaltyAndCheck(c.id);
    if (unlocks.length > 0) {
      loyaltyUnlocks.push({ cardId: c.id, cardName: c.name, milestones: unlocks });
    }
    const cardStats = battleResult.challengerTeamState.find(cs => cs.id === c.id);
    if (cardStats) {
      await updateLifetimeStats(c.id, {
        damageDealt: cardStats.statsDealtDamage || 0,
        won: playerWon,
        critsLanded: cardStats.statsCritsLanded || 0,
        passivesTriggered: cardStats.statsPassivesTriggered || 0,
      });
    }
  }

  return {
    battle,
    challengerTeam: cTeam,
    defenderTeam: dTeam,
    winnerSide: battleResult.winner,
    rewards,
    xpResult,
    log: battleResult.log,
    battleStats,
    loyaltyUnlocks,
  };
}

// Resolve a friend challenge
export async function resolveFriendBattle(
  battleId: string,
  defenderTeamCards: any[]
) {
  const battle = await prisma.battle.findUnique({
    where: { id: battleId },
    include: {
      challenger: true,
      defender: true,
    },
  });

  if (!battle) throw new Error('Battle not found');
  if (battle.status !== 'PENDING') throw new Error('Battle is not pending');

  const cTeamRaw = battle.challengerTeam as any as BattleCard[];
  const cTeam: BattleCard[] = cTeamRaw.map((c: any) => ({
    id: c.id,
    name: c.name,
    atk: c.atk,
    def: c.def,
    hp: c.hp,
    maxHp: c.maxHp || c.hp,
    stamina: c.stamina ?? 100,
    rarity: c.rarity,
    primaryLanguage: c.primaryLanguage,
    type: getCardType(c),
    avatarUrl: c.avatarUrl,
    loyaltyTier: c.loyaltyTier || 'none',
  }));
  const challengerAvgRank = getAverageRarityRank(cTeam);

  const dTeam: BattleCard[] = defenderTeamCards.map(c => ({
    id: c.id,
    name: c.name,
    atk: c.atk,
    def: c.def,
    hp: c.hp,
    maxHp: c.hp,
    stamina: c.stamina ?? 100,
    rarity: c.rarity as any,
    primaryLanguage: c.primaryLanguage,
    type: getCardType(c),
    avatarUrl: c.avatarUrl,
    loyaltyTier: c.loyaltyTier || 'none',
  }));
  const defenderAvgRank = getAverageRarityRank(dTeam);

  // Run the battle!
  const battleResult = resolve3v3Battle(cTeam, dTeam);
  const challengerWon = battleResult.winner === 'CHALLENGER';

  const winnerId = challengerWon ? battle.challengerId : battle.defenderId;

  // Calculate rewards for both players
  const challengerRewards = calculateRewards(
    challengerWon, 'OPEN',
    challengerWon ? challengerAvgRank : defenderAvgRank,
    challengerWon ? defenderAvgRank : challengerAvgRank
  );

  const defenderRewards = calculateRewards(
    !challengerWon, 'OPEN',
    !challengerWon ? defenderAvgRank : challengerAvgRank,
    !challengerWon ? challengerAvgRank : defenderAvgRank
  );

  // Update battle status
  const updatedBattle = await prisma.battle.update({
    where: { id: battleId },
    data: {
      defenderTeam: dTeam as any,
      log: battleResult.log as any,
      status: 'COMPLETED',
      winnerId,
      rewardBits: challengerRewards.bits + defenderRewards.bits,
      battleStats: [
        ...battleResult.challengerTeamState,
        ...battleResult.defenderTeamState
      ].map((c: any) => ({
        cardId: c.id,
        name: c.name,
        team: cTeam.some((ct: any) => ct.id === c.id) ? 'CHALLENGER' : 'DEFENDER',
        damageDealt: c.statsDealtDamage || 0,
        damageReceived: c.statsTakenDamage || 0,
        passivesTriggered: c.statsPassivesTriggered || 0,
        critsLanded: c.statsCritsLanded || 0,
        momentumAchieved: !!c.statsMomentumAchieved
      })) as any,
      completedAt: new Date(),
    },
    include: {
      challenger: true,
      defender: true,
    },
  });

  // Grant rewards to both players
  await prisma.user.update({
    where: { id: battle.challengerId },
    data: {
      currency: { increment: challengerRewards.bits },
    },
  });
  const challengerXpResult = await grantXP(battle.challengerId, challengerRewards.xp);

  if (battle.defenderId) {
    await prisma.user.update({
      where: { id: battle.defenderId },
      data: {
        currency: { increment: defenderRewards.bits },
      },
    });

    // We do not eagerly await defender XP to not block the challenger response,
    // in a real app this would be queued or handled correctly, but we'll await it here.
    await grantXP(battle.defenderId, defenderRewards.xp);

    // Update ratings for both players
    if (winnerId && battle.challenger && battle.defender) {
      const winner = winnerId === battle.challengerId ? battle.challenger : battle.defender;
      const loser = winnerId === battle.challengerId ? battle.defender : battle.challenger;

      if (winner && loser) {
        const { newWinnerRating, newLoserRating } = calculateNewRatings(winner.rating, loser.rating);
        await prisma.user.update({ where: { id: winner.id }, data: { rating: newWinnerRating } });
        await prisma.user.update({ where: { id: loser.id }, data: { rating: newLoserRating } });
      }
    }
  }

  // Deduct 20 stamina from all participating cards
  const now = new Date();
  for (const c of cTeamRaw as any as BattleCard[]) {
    await prisma.userCard.update({
      where: { id: c.id },
      data: { stamina: Math.max(0, c.stamina - 20), lastUsedAt: now }
    });
  }
  for (const c of dTeam) {
    await prisma.userCard.update({
      where: { id: c.id },
      data: { stamina: { decrement: 20 }, lastUsedAt: now }
    });
  }

  // --- Loyalty Processing for ALL participating cards ---
  const loyaltyUnlocks: { cardId: string; cardName: string; milestones: MilestoneUnlock[] }[] = [];
  const allCardsWithTeam = [
    ...cTeam.map(c => ({ card: c, team: 'CHALLENGER' as const })),
    ...dTeam.map(c => ({ card: c, team: 'DEFENDER' as const })),
  ];

  for (const { card: c, team } of allCardsWithTeam) {
    const unlocks = await incrementLoyaltyAndCheck(c.id);
    if (unlocks.length > 0) {
      loyaltyUnlocks.push({ cardId: c.id, cardName: c.name, milestones: unlocks });
    }
    const cardState = team === 'CHALLENGER'
      ? battleResult.challengerTeamState.find(cs => cs.id === c.id)
      : battleResult.defenderTeamState.find(cs => cs.id === c.id);
    if (cardState) {
      const didWin = (team === 'CHALLENGER' && challengerWon) || (team === 'DEFENDER' && !challengerWon);
      await updateLifetimeStats(c.id, {
        damageDealt: cardState.statsDealtDamage || 0,
        won: didWin,
        critsLanded: cardState.statsCritsLanded || 0,
        passivesTriggered: cardState.statsPassivesTriggered || 0,
      });
    }
  }

  return {
    battle: updatedBattle,
    winnerSide: battleResult.winner,
    challengerRewards,
    defenderRewards,
    xpResult: challengerXpResult,
    log: battleResult.log,
    loyaltyUnlocks,
  };
}

import { prisma } from './prisma';
import { getRandomDevelopersByRarity, searchUsersForPackWithRarity } from './githubService';
import { getPackById } from './packDefinitions';

const RARITY_ORDER = ['Common', 'Uncommon', 'Rare', 'Epic', 'Legendary'];

function rollRarity(): string {
  const roll = Math.random() * 100;
  if (roll < 0.3) return 'Legendary';  // 0.3%  (was 1%)
  if (roll < 2.3) return 'Epic';       // 2%    (was 4%)
  if (roll < 10.3) return 'Rare';      // 8%    (was 10%)
  if (roll < 30.3) return 'Uncommon';  // 20%   (was 25%)
  return 'Common';                     // ~69.7% (was 60%)
}

function ensureMinimumRarity(rarities: string[], minRarity: string): string[] {
  const minIdx = RARITY_ORDER.indexOf(minRarity);
  const hasMinimum = rarities.some(r => RARITY_ORDER.indexOf(r) >= minIdx);

  if (!hasMinimum) {
    // Upgrade the lowest card to the guaranteed minimum
    let lowestIdx = 0;
    let lowestRank = RARITY_ORDER.indexOf(rarities[0]);
    for (let i = 1; i < rarities.length; i++) {
      const rank = RARITY_ORDER.indexOf(rarities[i]);
      if (rank < lowestRank) {
        lowestRank = rank;
        lowestIdx = i;
      }
    }
    rarities[lowestIdx] = minRarity;
  }

  return rarities;
}

const FRAGMENTS_PER_RARITY: Record<string, number> = {
  'Common': 5,
  'Uncommon': 10,
  'Rare': 20,
  'Epic': 40,
  'Legendary': 80
};

export async function openBoosterPack(userId: string, packId?: string) {
  const pack = packId ? getPackById(packId) : null;
  const cardsToPull = pack?.cardCount ?? 5;

  let pickedRarities: string[] = [];

  if (pack?.allCommon) {
    pickedRarities = Array(cardsToPull).fill('Common');
  } else {
    for (let i = 0; i < cardsToPull; i++) {
      pickedRarities.push(rollRarity());
    }
    if (pack?.guaranteedMinRarity) {
      pickedRarities = ensureMinimumRarity(pickedRarities, pack.guaranteedMinRarity);
    }
  }

  let newCards = [];

  if (pack) {
    const query = pack.buildQuery();

    // Group the picked rarities so we can fetch them in appropriately sized requests
    const rarityCounts = pickedRarities.reduce((acc, curr) => {
      acc[curr] = (acc[curr] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    for (const [rarity, count] of Object.entries(rarityCounts)) {
      const devs = await searchUsersForPackWithRarity(query, rarity, count);

      // If the specific pack query failed to find enough devs of this rarity,
      // pad with general random devs of the same rarity
      for (let i = 0; i < count; i++) {
        let dev = devs[i];
        if (!dev) {
          const fallbacks = await getRandomDevelopersByRarity(rarity, 1);
          dev = fallbacks[0];
        }

        if (dev) {
          const card = await upsertCard(dev);
          const userCardResult = await addCardToUser(userId, card);
          newCards.push({ 
            ...dev, 
            isShiny: userCardResult.isShiny, 
            userCardId: userCardResult.id,
            isDuplicate: userCardResult.isDuplicate,
            fragmentsEarned: userCardResult.fragmentsEarned
          });
        }
      }
    }
  } else {
    const rarityCounts = pickedRarities.reduce((acc, curr) => {
      acc[curr] = (acc[curr] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    for (const [rarity, count] of Object.entries(rarityCounts)) {
      const devs = await getRandomDevelopersByRarity(rarity, count);
      for (const dev of devs) {
        const card = await upsertCard(dev);
        const userCardResult = await addCardToUser(userId, card);
        newCards.push({ 
          ...dev, 
          isShiny: userCardResult.isShiny, 
          userCardId: userCardResult.id,
          isDuplicate: userCardResult.isDuplicate,
          fragmentsEarned: userCardResult.fragmentsEarned
        });
      }
    }
  }

  // Handle 15% Pack Drop for Fragments
  let packDropFragments = null;
  if (Math.random() < 0.15 && newCards.length > 0) {
    // Determine language mapping
    let dropLang = pack?.themeLanguage;
    if (!dropLang) {
      // Find most common language in this pack context
      const langCounts: Record<string, number> = {};
      for (const c of newCards) {
        if (c.primaryLanguage && c.primaryLanguage !== 'Unknown') {
          langCounts[c.primaryLanguage] = (langCounts[c.primaryLanguage] || 0) + 1;
        }
      }
      const sortedLangs = Object.entries(langCounts).sort((a, b) => b[1] - a[1]);
      if (sortedLangs.length > 0) {
        dropLang = sortedLangs[0][0];
      }
    }

    if (dropLang && dropLang !== 'Unknown') {
      const dropAmount = 20; // Example standard pack drop amount
      packDropFragments = {
        language: dropLang,
        amount: dropAmount
      };

      const user = await prisma.user.findUnique({ where: { id: userId }});
      if (user) {
        const fragments = (user.fragments && typeof user.fragments === 'object' && !Array.isArray(user.fragments) ? user.fragments : {}) as Record<string, number>;
        fragments[dropLang] = (fragments[dropLang] || 0) + dropAmount;

        const logs = Array.isArray(user.fragmentLogs) ? [...user.fragmentLogs] : [];
        logs.unshift({
          date: new Date().toISOString(),
          source: `Pack drop - ${pack?.name || 'Generic Booster'}`,
          language: dropLang,
          amount: dropAmount
        });

        await prisma.user.update({
          where: { id: userId },
          data: { fragments, fragmentLogs: logs }
        });
      }
    }
  }

  return { newCards, packDropFragments };
}

async function upsertCard(dev: any) {
  let card = await prisma.card.findUnique({
    where: { githubUsername: dev.githubUsername }
  });

  if (!card) {
    card = await prisma.card.create({ data: dev });
  }

  return card;
}

async function addCardToUser(userId: string, card: any) {
  const existingCard = await prisma.userCard.findFirst({
    where: { userId, cardId: card.id }
  });

  const isShiny = Math.random() < 0.05;

  if (existingCard) {
    const lang = card.primaryLanguage || 'Unknown';
    if (lang !== 'Unknown') {
      const amount = FRAGMENTS_PER_RARITY[card.rarity] || 5;

      const user = await prisma.user.findUnique({ where: { id: userId }});
      if (user) {
        const fragments = (user.fragments && typeof user.fragments === 'object' && !Array.isArray(user.fragments) ? user.fragments : {}) as Record<string, number>;
        fragments[lang] = (fragments[lang] || 0) + amount;

        const logs = Array.isArray(user.fragmentLogs) ? [...user.fragmentLogs] : [];
        logs.unshift({
          date: new Date().toISOString(),
          source: `Duplicate - ${card.rarity} ${lang} card`,
          language: lang,
          amount: amount
        });

        await prisma.user.update({
          where: { id: userId },
          data: { fragments, fragmentLogs: logs }
        });

        return { isShiny: existingCard.isShiny, id: existingCard.id, isDuplicate: true, fragmentsEarned: amount, language: lang };
      }
    }
    return { isShiny: existingCard.isShiny, id: existingCard.id, isDuplicate: true, fragmentsEarned: 0, language: 'Unknown' };
  }

  const newCard = await prisma.userCard.create({
    data: { userId, cardId: card.id, isShiny }
  });
  return { isShiny, id: newCard.id, isDuplicate: false, fragmentsEarned: 0, language: card.primaryLanguage };
}

import axios from 'axios';

const GITHUB_TOKEN = process.env.GITHUB_TOKEN;
const API_BASE = 'https://api.github.com';

const headers = {
  Authorization: GITHUB_TOKEN ? `token ${GITHUB_TOKEN}` : '',
  Accept: 'application/vnd.github.v3+json',
};

// Check if token is missing in production to prevent silent rate-limit bans
if (!GITHUB_TOKEN && process.env.NODE_ENV === 'production') {
  console.warn("WARNING: GITHUB_TOKEN is not set. API rate limits will be severely restricted.");
}

// Caching to memory to avoid ratelimits during local dev
import NodeCache from 'node-cache';
export const cache = new NodeCache({ stdTTL: 86400 });

export async function fetchGitHubUserStats(username: string, expectedRarity?: string) {
  const cacheKey = expectedRarity ? `user_stats_${username}_${expectedRarity}` : `user_stats_${username}`;
  if (cache.has(cacheKey)) {
    return cache.get(cacheKey) as any;
  }

  try {
    const userRes = await axios.get(`${API_BASE}/users/${username}`, { headers });
    const user = userRes.data;

    // limited to 1 page for speed
    const reposRes = await axios.get(`${API_BASE}/users/${username}/repos?per_page=100`, { headers });
    const repos = reposRes.data;

    let totalStars = 0;
    let totalForks = 0;
    const languages: Record<string, number> = {};

    for (const repo of repos) {
      totalStars += repo.stargazers_count;
      totalForks += repo.forks_count;
      if (repo.language) {
        languages[repo.language] = (languages[repo.language] || 0) + 1;
      }
    }

    const primaryLanguage = Object.keys(languages).sort((a, b) => languages[b] - languages[a])[0] || 'Unknown';

    const accountAgeMs = new Date().getTime() - new Date(user.created_at).getTime();
    const accountAgeYears = accountAgeMs / (1000 * 60 * 60 * 24 * 365.25);

    // Rebalanced stat formulas (sqrt compression for balanced battles)
    const baseAtk = Math.floor((Math.sqrt(totalStars) * 2 + Math.sqrt(totalForks)) * 10) + 10;
    const baseDef = Math.floor(user.public_repos * 15 + (user.public_gists || 0) * 20) + Math.floor(user.followers * 0.5) + 50;
    const baseHp = Math.floor(accountAgeYears * 50) + Math.floor(user.public_repos * 5) + 200 + Math.floor(baseAtk * 3);

    // Rarity determination
    let rarity = expectedRarity || 'Common';

    // Only calculate natural rarity if one wasn't explicitly requested by a pack drop
    if (!expectedRarity) {
      const score = user.followers * 2 + totalStars;
      if (score > 50000 || (user.company && ['google', 'microsoft', 'vercel', 'facebook', 'meta'].some(c => user.company.toLowerCase().includes(c)))) {
        rarity = 'Legendary';
      } else if (score > 10000) {
        rarity = 'Epic';
      } else if (score > 2500) {
        rarity = 'Rare';
      } else if (score > 500) {
        rarity = 'Uncommon';
      }
    }

    // Apply rarity multipliers so low-rarity cards are definitively weaker
    const rarityMultipliers: Record<string, number> = {
      'Common': 0.5,
      'Uncommon': 0.8,
      'Rare': 1.2,
      'Epic': 1.8,
      'Legendary': 2.5
    };
    const multiplier = rarityMultipliers[rarity] || 1.0;

    const atk = Math.max(10, Math.floor(baseAtk * multiplier));
    const def = Math.max(10, Math.floor(baseDef * multiplier));
    const hp = Math.max(50, Math.floor(baseHp * multiplier));

    const flavorText = user.bio || `Master of the ${primaryLanguage} shadows.`;

    const stats = {
      githubUsername: user.login,
      avatarUrl: user.avatar_url,
      name: user.name || user.login,
      flavorText,
      atk,
      def,
      hp,
      rarity,
      primaryLanguage
    };

    cache.set(cacheKey, stats);
    return stats;

  } catch (err) {
    console.error(`Error fetching user ${username}`, err);
    return null;
  }
}

export async function searchUsersForPackWithRarity(baseQuery: string, rarity: string, count: number): Promise<any[]> {
  // Append rarity followers constraint to the base query
  let query = baseQuery;
  if (rarity === 'Legendary') query += ' followers:>25000';
  else if (rarity === 'Epic') query += ' followers:5000..25000';
  else if (rarity === 'Rare') query += ' followers:1000..5000';
  else if (rarity === 'Uncommon') query += ' followers:200..1000';
  else query += ' followers:<200';

  const page = Math.floor(Math.random() * 5) + 1; // Limit page randomization for safer matching
  const searchUrl = `${API_BASE}/search/users?q=${encodeURIComponent(query)}&per_page=${Math.min(count * 5, 30)}&page=${page}`;

  try {
    const res = await axios.get(searchUrl, { headers });
    const users = res.data.items || [];

    // Shuffle and take the required count
    const shuffled = users.sort(() => 0.5 - Math.random()).slice(0, count);

    const results = [];
    for (const u of shuffled) {
      const stats = await fetchGitHubUserStats(u.login, rarity);
      if (stats) results.push(stats);
    }
    return results;

  } catch (err) {
    console.error('Error searching users for pack with rarity', err);
    return [];
  }
}

export async function getRandomDevelopersByRarity(rarity: string, limit: number = 1): Promise<any[]> {
  // Query strings to match rarity bands
  let query = 'type:user';
  if (rarity === 'Legendary') query += ' followers:>25000';
  else if (rarity === 'Epic') query += ' followers:5000..25000';
  else if (rarity === 'Rare') query += ' followers:1000..5000';
  else if (rarity === 'Uncommon') query += ' followers:200..1000';
  else query += ' followers:<200';

  // pick a random page up to 10 (since pagination limit might apply)
  const page = Math.floor(Math.random() * 10) + 1;
  const searchUrl = `${API_BASE}/search/users?q=${encodeURIComponent(query)}&per_page=${limit}&page=${page}`;

  try {
    const res = await axios.get(searchUrl, { headers });
    const users = res.data.items;

    // We get only usernames, we need to fetch their full stats
    const results = [];
    for (const u of users) {
      const stats = await fetchGitHubUserStats(u.login, rarity);
      if (stats) results.push(stats);
    }
    return results;

  } catch (err) {
    console.error(`Error searching users for rarity ${rarity}`, err);
    return [];
  }
}

